var documenterSearchIndex = {"docs":
[{"location":"user/composite_dsl/#composite_dsl_user","page":"Composite DSL","title":"Composite DSL","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The composite DSL builds CompositeAlgorithm and Routine values from a block syntax. It is a constructor shorthand: entries still become normal algorithms, states, routes, shares, and schedules.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @CompositeAlgorithm when child entries should run on interval schedules. Use @Routine when child entries should run sequentially with repeat counts.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 3\n    @alias source = SourceAlgo\n\n    produced, passthrough = source(seed = seed)\n    doubled = @interval 10 double(produced)\n    Sink(value = doubled)\nend","category":"page"},{"location":"user/composite_dsl/#Inline-State","page":"Composite DSL","title":"Inline State","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Declare local state with @state.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state equilibrium_state\n    @state clamping_beta = 0.0\n    @state buffers = Float64[]\n\n    Step(value = clamping_beta)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Fields without defaults are required during init. Fields with defaults are rebuilt for each process initialization.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"You can also give the inline state an explicit key:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state learning_state begin\n        loss = 0.0\n        buffer = Float64[]\n    end\n\n    Logger(value = loss)\nend","category":"page"},{"location":"user/composite_dsl/#Runtime-Inputs","page":"Composite DSL","title":"Runtime Inputs","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Declare per-run values with @input.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state energy = 0.0\n    @input temperature::AbstractFloat\n    @input sweep = 1\n\n    accepted = metropolis_step(energy, temperature; sweep = sweep)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Runtime inputs are supplied to run as keyword arguments:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"p = Process(algo; repeats = 100)\nrun(p; temperature = 2.0)","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"They are validated once before the loop starts and are visible during the run through the transient ProcessContext._input field. They are not stored in the initialized loop algorithm or finished process context after the run.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Forms:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@input required_name\n@input typed_name::AbstractFloat\n@input defaulted_name = 1","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use runtime @input for scalar parameters or small values that can change from run to run. Use @state or Init(...) for persistent buffers and setup data.","category":"page"},{"location":"user/composite_dsl/#Aliases","page":"Composite DSL","title":"Aliases","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @alias to name an algorithm constructor or value for later DSL entries.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @alias dynamics = Metropolis(model)\n    @alias capture = Capturer()\n\n    state = dynamics()\n    capture(value = state)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Aliases are macro-time names. They affect later uses of the alias in the DSL; they are not runtime variables.","category":"page"},{"location":"user/composite_dsl/#Function-Calls","page":"Composite DSL","title":"Function Calls","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Plain Julia function calls are wrapped in a small process algorithm.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state x = 2\n    y = sqrt(x)\n    z = scale_value(y; scale = 3)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Known DSL names such as x and y are routed from context. Other Julia values are captured into the wrapper.","category":"page"},{"location":"user/composite_dsl/#Algorithm-Routes","page":"Composite DSL","title":"Algorithm Routes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Keyword arguments to process algorithms are route declarations.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 3\n    produced = Source(seed = seed)\n    Sink(value = produced)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Sink(value = produced) routes produced into the target as value.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Process algorithms created with @ProcessAlgorithm can also use direct positional syntax when their positional argument names are known:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state value = 1\n    MyGeneratedAlgo(value)\nend","category":"page"},{"location":"user/composite_dsl/#Transform-Routes","page":"Composite DSL","title":"Transform Routes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use explicit @transform(f, source) when a routed value should be transformed before it reaches the target.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state clamping_beta = 2.0\n    SetBeta(value = @transform(x -> -x, clamping_beta))\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The source can be a normal DSL symbol or an owned-field reference:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context c = nested()\n    result = identity(@transform(x -> x + 1, c.capture.value))\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Transforms are route syntax, not general Julia expression syntax. Write @transform(x -> -x, clamping_beta), not -clamping_beta, when the value must come from the process context.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use an explicit @route statement when a transformed route also needs writeback through a reverse transform:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @alias source = SourceAlgo\n    @alias target = TargetAlgo\n\n    source()\n    target()\n\n    @route source.value => target.input transform = x -> 2x reverse_transform = y -> y / 2\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Here target reads input through the forward transform. If it returns (; input = new_input), the source field value is updated through reverse_transform.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@transform(f, source) is read-transform syntax for call arguments. Reverse writeback uses @route ... reverse_transform = g.","category":"page"},{"location":"user/composite_dsl/#Ref-and-Indexed-Reads","page":"Composite DSL","title":"Ref and Indexed Reads","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Indexed reads from context values are routed as transform routes.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state clamping_beta = Ref(2.0)\n    Sink(value = clamping_beta[])\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This routes clamping_beta and applies getindex before the target sees it. The same shape works with indexes and ranges:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state buffer = [1, 2, 3]\n    first_value = identity(buffer[1])\n    tail = identity(buffer[2:3])\nend","category":"page"},{"location":"user/composite_dsl/#Direct-State-Writes","page":"Composite DSL","title":"Direct State Writes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Assigning a captured Julia value to an inline state field lowers to a ContextWrite widget.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"somevar = 3\n\nalgo = @Routine begin\n    @state clamping_beta = 1.0\n    clamping_beta = somevar\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The assignment captures somevar when the loop algorithm is constructed. At step time, the value is converted to the current context field type when the field already exists.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If the right-hand side is a context value, route it explicitly through normal DSL syntax:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state source = 2.0\n    @state target = 0.0\n    target = source\nend","category":"page"},{"location":"user/composite_dsl/#Indexed-Mutation","page":"Composite DSL","title":"Indexed Mutation","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use normal indexed assignment to mutate buffers stored in context.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @state buffer = [0, 0, 0]\n\n    buffer[1] = 2\n    buffer[2:3] = [4, 5]\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This lowers to a wrapped setindex! call. The buffer itself is routed from the context, then mutated in place.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Indexes may be literals, variables captured from the surrounding Julia scope, or ranges:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"idx = 2\n\nalgo = @Routine begin\n    @state buffer = [0, 0, 0]\n    buffer[idx] = 9\nend","category":"page"},{"location":"user/composite_dsl/#Broadcast-Mutation","page":"Composite DSL","title":"Broadcast Mutation","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Broadcast assignment is also supported for context buffers.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"replacement = [7, 8]\n\nalgo = @Routine begin\n    @state buffer = [0, 0, 0]\n\n    buffer .= 1\n    buffer[2:3] .= replacement\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Whole-buffer broadcast lowers to context_broadcast!(buffer, value). Indexed broadcast lowers through view(buffer, inds...), so range writes mutate the original buffer rather than a copied slice.","category":"page"},{"location":"user/composite_dsl/#Owned-Field-Reads","page":"Composite DSL","title":"Owned Field Reads","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use dotted references to read fields owned by aliased algorithms or nested contexts.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @Routine begin\n    @alias dynamics = Dynamics()\n\n    seen = Sink(value = dynamics.state)\n    state = dynamics()\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The special binding form:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"state = dynamics.state","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"exposes the owned field under the plain DSL name state for later statements.","category":"page"},{"location":"user/composite_dsl/#Owned-Field-Writes","page":"Composite DSL","title":"Owned Field Writes","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"You can assign to an owned field target.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"nudged = @Routine begin\n    @state nudged_beta = 0.0\n    Step(beta = nudged_beta)\nend\n\nalgo = @CompositeAlgorithm begin\n    @state clamping_beta = Ref(2.0)\n    @alias nudged = nudged\n\n    nudged.nudged_beta = clamping_beta[]\n    nudged()\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This creates a ContextWrite entry and routes the assigned value into it. For a nested routine's inline state, the write targets the nested state field through the normal route and merge machinery.","category":"page"},{"location":"user/composite_dsl/#Explicit-State-Sharing","page":"Composite DSL","title":"Explicit State Sharing","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Nested DSL blocks can independently declare the same state field. That remains compatible, but the merge now warns unless the parent documents the intended sharing.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @bind when the parent block owns, defaults, or requires the shared state and a child block should use that same slot.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@bind buffers => f.buffers","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This says: the current block's buffers state slot and child context f's inline buffers state slot are intentionally the same resource.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"forward = @Routine begin\n    @state buffers\n    buffers = fill_forward!(buffers)\nend\n\nnudged = @Routine begin\n    @state buffers\n    buffers = read_nudged!(buffers)\nend\n\nalgo = @CompositeAlgorithm begin\n    @state buffers = make_buffers()\n\n    @context f = forward()\n    @context n = nudged()\n\n    @bind buffers => f.buffers\n    @bind buffers => n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"In this example, algo creates the buffer with make_buffers(). Both child routines declare @state buffers because each routine is still a reusable building block with a local contract, but the parent explicitly binds both child contracts to the parent-owned state slot.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @merge when child blocks should share with each other and the parent does not need to declare a separate state slot:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@merge f.buffers, n.buffers","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"This says: child context f's inline buffers slot and child context n's inline buffers slot are intentionally the same resource.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context f = forward()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If neither child supplies a default, the merged field remains required:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context f = forward()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend\n\nresolved = resolve(algo)\ninitialized = init(resolved, Init(:_state; buffers = make_buffers()))","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If one side has a default and the other side is required, the default satisfies the merged slot:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"forward_with_default = @Routine begin\n    @state buffers = make_buffers()\n    buffers = fill_forward!(buffers)\nend\n\nalgo = @CompositeAlgorithm begin\n    @context f = forward_with_default()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"If multiple merged slots provide defaults for the same field, construction still continues but warns because the later default wins. Prefer a single parent default with @bind when ownership is clear.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Selectors are written against @context aliases and must appear after the context has been declared:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @context f = forward()\n    @context n = nudged()\n\n    @merge f.buffers, n.buffers\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"f.buffers is transparent syntax for the nested inline state field f._state.buffers; both forms are accepted:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@merge f._state.buffers, n.buffers\n@bind buffers => f._state.buffers","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @bind for parent-to-child sharing. Use @merge for peer child-to-child sharing. Without either declaration, overlapping child state fields are still merged for compatibility, but the DSL warns with paths such as f.buffers <=> n.buffers and suggests an explicit @bind or @merge.","category":"page"},{"location":"user/composite_dsl/#Context-Aliases","page":"Composite DSL","title":"Context Aliases","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @context when later statements need to refer to the subcontext produced by a nested DSL entry.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"plus = @Routine begin\n    @alias capture = Capturer()\n    capture()\nend\n\nalgo = @CompositeAlgorithm begin\n    @context c1 = plus()\n    result = identity(c1.capture.value)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@context is only a macro-time reference. The wrapped entry still runs as the right-hand side expression says.","category":"page"},{"location":"user/composite_dsl/#Full-Context-Shares","page":"Composite DSL","title":"Full-Context Shares","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @all(source) or @all(source...) in an algorithm call to lower to a normal Share.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @alias source = Source\n    source()\n    Consumer(@all(source...))\nend","category":"page"},{"location":"user/composite_dsl/#Scheduling","page":"Composite DSL","title":"Scheduling","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Inside @CompositeAlgorithm, use @interval or @every on the right-hand side of an entry.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state value = 1\n    sampled = @interval 10 Sample(value)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Inside @Routine, use @repeat.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"routine = @Routine begin\n    @state value = 1\n    value = @repeat 5 Step(value = value)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@repeat also accepts the normal lifetime constructors. When a lifetime selector is written as a DSL variable, the DSL resolves it to the corresponding Var(...) selector:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"routine = @Routine begin\n    count = @repeat Until(x -> x >= 100, count) Counter()\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Supported forms are Repeat(n), Indefinite(), Until(condition, selector), RepeatOrUntil(condition, n, selector), AtLeast(condition, n, selector), and AtLeastAtMost(condition, min, max, selector).","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"For repeated sub-blocks:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state value = 1\n\n    result = @repeat 3 begin\n        value = Step(value = value)\n        value = Step(value = value)\n    end\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Write schedules on the right-hand side:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"value = @interval 10 Step(value = value)","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"not:","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@interval 10 value = Step(value = value)","category":"page"},{"location":"user/composite_dsl/#Conditional-Entries","page":"Composite DSL","title":"Conditional Entries","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use @include_if to include or skip entries when constructing the loop algorithm.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 3\n    @include_if include_source produced = Source(seed = seed)\n    Sink(value = seed)\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"The condition is evaluated at construction time. Skipped entries are not registered and do not contribute routes, shares, or schedules.","category":"page"},{"location":"user/composite_dsl/#Final-Post-Processing","page":"Composite DSL","title":"Final Post-Processing","text":"","category":"section"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"Use one root-level @finally to wrap the outer algorithm with a final post-processing function.","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"algo = @CompositeAlgorithm begin\n    @state seed = 8\n    Sink(value = seed)\n    @finally summarize_context\nend","category":"page"},{"location":"user/composite_dsl/","page":"Composite DSL","title":"Composite DSL","text":"@finally is only valid at the outer DSL block level.","category":"page"},{"location":"user/interactive/#interactive_user","page":"Interactive Contexts","title":"Interactive Contexts","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"ContextExchange gives external code a polled read/write handle to selected process variables.","category":"page"},{"location":"user/interactive/#Selectors","page":"Interactive Contexts","title":"Selectors","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Add a ContextExchange child and pass its Var selectors as init-only vars:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"algo = resolve(CompositeAlgorithm(\n    :target => MyAlgo(),\n    :_exchange => ContextExchange(),\n    (1, 20),\n))\n\ncontext = Processes.context(init(\n    algo,\n    Init(:_exchange; vars = (Var(:target, :value), Var(:target, :seen))),\n))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Selectors are resolved during initcontext, when the registry and concrete state layout are available. The resolved paths are stored in the exchange state type, and ContextExchange uses a custom _step! instead of route/wiring machinery.","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"For a different external name, use a pair:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Init(:_exchange; vars = (:display => Var(:target, :value),))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Type selectors are also supported when they resolve uniquely:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Init(:_exchange; vars = (:display => Var(MyAlgo, :value),))","category":"page"},{"location":"user/interactive/#Polling-And-Writes","page":"Interactive Contexts","title":"Polling And Writes","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"External code reads and writes exchange-local names:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"ref = view(context, :value)\nref[]          # last published value, initialized from the target field\nref[] = 4      # queued write","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The next due exchange step converts pending writes to the current target field type and writes directly into the resolved subcontext. Current values are also published to the ref slots on due exchange steps.","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Programmatic writes use the same names:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"interact!(context, :value => 5)\ninteract!(process, :value => 5)","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"Default lookup expects one ContextExchange in the process. If there are multiple exchanges, pass the exchange key explicitly.","category":"page"},{"location":"user/interactive/#Scheduling","page":"Interactive Contexts","title":"Scheduling","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The outer loop schedule still controls how often the exchange child is called:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"CompositeAlgorithm(target, :_exchange => ContextExchange(), (1, 20))\nProcesses.context(init(algo, Init(:_exchange; vars = (Var(:target, :value),))))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The exchange also supports a wall-clock gate:","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"ContextExchange(; period = 0.05)\nInit(:_exchange; vars = (Var(:target, :value),))","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"If the exchange is called before period seconds have elapsed, it returns without reading selected variables or applying pending writes.","category":"page"},{"location":"user/interactive/#Complete-Example","page":"Interactive Contexts","title":"Complete Example","text":"","category":"section"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"using Processes\n\nstruct InteractiveTarget <: ProcessAlgorithm end\n\nfunction Processes.init(::InteractiveTarget, context)\n    return (; value = 1.0)\nend\n\nfunction Processes.step!(::InteractiveTarget, context)\n    return (;)\nend\n\nalgo = resolve(CompositeAlgorithm(\n    :target => InteractiveTarget(),\n    :_exchange => ContextExchange(),\n    (1, 1),\n))\n\ncontext = Processes.context(init(\n    algo,\n    Init(:_exchange; vars = (Var(:target, :value),));\n    lifetime = Repeat(3),\n))\nref = view(context, :value)\n\nref[] == 1.0\n\nref[] = 4\ncontext = Processes._step!(algo, context, Processes.Stable())\n\nref[] == 4.0\ncontext.target.value == 4.0","category":"page"},{"location":"user/interactive/","page":"Interactive Contexts","title":"Interactive Contexts","text":"The interactive API is covered in test/ContextExchangeTest.jl.","category":"page"},{"location":"user/copying_and_management/#copying_processes_user","page":"Copying Processes","title":"Copying Processes","text":"","category":"section"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"This page documents the process-copy helpers.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"A process copy is rebuilt from saved construction data, not by copying the live context directly. This matters when a context was initialized from external storage, buffers, or data views.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"If you want to run many independent jobs through reusable processes on Julia threads, see Threaded Process Managers.","category":"page"},{"location":"user/copying_and_management/#Why-Copy-Instead-of-deepcopy","page":"Copying Processes","title":"Why Copy Instead of deepcopy","text":"","category":"section"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"Process contexts are often built from Init(...) values that point at external storage, buffers, or data views. A raw deepcopy of the live context can therefore copy the wrong thing or preserve sharing that should be rebuilt per process.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"The copying helpers work from the initialized loop algorithm and the normal lifecycle init pipeline instead:","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"copy the stored loop algorithm recipe,\nreplace selected inputs and overrides,\ninitialize a fresh context for each copy.","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"The saved recipe is the initialized loop algorithm: it stores the resolved algorithm, persistent context, and replayable Init/Override specs.","category":"page"},{"location":"user/copying_and_management/#Copy-APIs","page":"Copying Processes","title":"Copy APIs","text":"","category":"section"},{"location":"user/copying_and_management/#Processes.copyinputs","page":"Copying Processes","title":"Processes.copyinputs","text":"copyinputs(process_or_la)\n\nReturn the stored Init specs for an initialized process or loop algorithm.\n\n\n\n\n\n","category":"function"},{"location":"user/copying_and_management/#Processes.copyoverrides","page":"Copying Processes","title":"Processes.copyoverrides","text":"copyoverrides(process_or_la)\n\nReturn the stored Override specs for an initialized process or loop algorithm.\n\n\n\n\n\n","category":"function"},{"location":"user/copying_and_management/#Processes.copyprocess","page":"Copying Processes","title":"Processes.copyprocess","text":"copyprocess(p::Process, Init(...), Override(...); kwargs...)\n\nBuild a new process from the stored initialized loop algorithm recipe. Extra init/override specs are merged by init.\n\n\n\n\n\n","category":"function"},{"location":"user/copying_and_management/#Typical-Copy-Pattern","page":"Copying Processes","title":"Typical Copy Pattern","text":"","category":"section"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"template = Process(\n    MyAlgo,\n    Init(MyAlgo; start = 0, buffer = Int[]),\n    Override(MyAlgo; delta = 2);\n    repeats = 10,\n)\n\np = copyprocess(\n    template,\n    Init(MyAlgo; start = 100, buffer = Int[]),\n)\n\nrun(p)\nwait(p)\nclose(p)","category":"page"},{"location":"user/copying_and_management/","page":"Copying Processes","title":"Copying Processes","text":"If the context needs custom rebuilding logic, provide a fully prepared context = ... directly.","category":"page"},{"location":"user/contexts/#contexts_user","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"","category":"section"},{"location":"user/contexts/#What-You-Receive-in-init/step!/cleanup","page":"Contexts and Indexing","title":"What You Receive in init/step!/cleanup","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"The full runtime data object is a ProcessContext.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Each registered algorithm or state owns one named part of that context. That part is a SubContext.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Entity methods receive a SubContextView, not the raw ProcessContext. A view shows the values that the current entity is allowed to read. Those values can come from its own subcontext, from a Route, from a Share, or from temporary values supplied by the package.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"That view exposes:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"local subcontext variables,\nrouted/shared variables,\nglobals via getglobals(context).","category":"page"},{"location":"user/contexts/#Reading-Variables","page":"Contexts and Indexing","title":"Reading Variables","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"function Processes.step!(::MyAlgo, context)\n    (; state, dt) = context\n    # ...\n    return (;)\nend","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"context.name and destructuring both read from the view.","category":"page"},{"location":"user/contexts/#Writing-Variables","page":"Contexts and Indexing","title":"Writing Variables","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Return a NamedTuple from step!/init/cleanup.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Existing names update mapped targets.\nNew names are added to local subcontext.\nType changes are rejected once the stable loop is running.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"If Target sees source_value through a route and returns (; source_value = 2.0), the stored value in the source subcontext is updated. If it returns (; new_local_value = 2.0), that value is added to Target's own subcontext.","category":"page"},{"location":"user/contexts/#Top-Level-Context-Access","page":"Contexts and Indexing","title":"Top-Level Context Access","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"From a process:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"ctx = context(p)","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"context(p) returns the stored persistent context. getcontext(p) returns a runtime-flavored context with the process injected into globals.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"From a context, index by:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"symbol key: ctx[:Fib_1]\nregistered value/type: ctx[Fib], ctx[Fib()], ctx[my_unique_fib]","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Object and type lookup use the same identity rules as Input, Override, Route, and Share. See Referencing Algorithms.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Related symbol-based lookup also works on resolved loop algorithms and registries:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"resolved = resolve(CompositeAlgorithm(Fib, Noise, (1, 2)))\nreg = getregistry(resolved)\n\nresolved[:Fib_1]   # same object as resolved.Fib_1\nreg[:Fib_1]        # registered IdentifiableAlgo\nctx[:Fib_1]        # subcontext","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Use loop-algorithm indexing when you want the registered algorithm or state object, and context indexing when you want its current stored data.","category":"page"},{"location":"user/contexts/#Re-Initializing-One-Subcontext","page":"Contexts and Indexing","title":"Re-Initializing One Subcontext","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"You can re-run init for one registered algorithm inside an existing context:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"ctx = initcontext(resolved)\n\nctx = initcontext(ctx, :Fib_1)\nctx = initcontext(ctx, :Fib_1; inputs = (; seed = 123))\nctx = initcontext(ctx, resolved[:Fib_1]; overrides = (; value = 0.0))","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"This updates only the targeted subcontext.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"inputs are merged into that subcontext before init(...) runs.\noverrides are merged into that subcontext after init(...) returns.","category":"page"},{"location":"user/contexts/#Globals","page":"Contexts and Indexing","title":"Globals","text":"","category":"section"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"ProcessContext includes a globals field.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Common globals:","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"lifetime\nalgo\nprocess (in runtime loop context)","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"Use getglobals(context) inside entity methods when you need them. Globals are process-level values, not values owned by one algorithm.","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"You can also select globals with Var(:name) in APIs like Until(...). See Vars (Var Selectors).","category":"page"},{"location":"user/contexts/","page":"Contexts and Indexing","title":"Contexts and Indexing","text":"For buffered external writes through ContextExchange and ref-like view(context, Var(...)) handles, see Interactive Contexts.","category":"page"},{"location":"user/vars/#vars_user","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var is a small selector object used to say \"read this stored value later\".","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"It is most often used by lifetimes such as Until, where the stop condition needs one value from the current context.","category":"page"},{"location":"user/vars/#Two-Forms","page":"Vars (Var Selectors)","title":"Two Forms","text":"","category":"section"},{"location":"user/vars/#1.-Subcontext-variable","page":"Vars (Var Selectors)","title":"1. Subcontext variable","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(entity_ref, :name)","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"This reads :name from the subcontext of entity_ref. Use the same entity_ref style you used when building the process: type, saved instance, saved Unique(...) value, or symbol key.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Example:","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"counter = Counter()\nVar(counter, :count)","category":"page"},{"location":"user/vars/#2.-Global-variable","page":"Vars (Var Selectors)","title":"2. Global variable","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(:name)","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"This reads :name from context.globals.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"So:","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(:process) reads context.globals.process\nVar(:algo) reads context.globals.algo\nVar(:lifetime) reads context.globals.lifetime","category":"page"},{"location":"user/vars/#Common-Use-in-Until","page":"Vars (Var Selectors)","title":"Common Use in Until","text":"","category":"section"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var is commonly used with Until(...) to pick what value the stop condition should inspect.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Example with a subcontext variable:","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"counter = Counter()\n\nlifetime = Until(x -> x >= 100, Var(counter, :count))","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Example with a global variable (process object):","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"lifetime = Until(p -> loopidx(p) >= 10_000, Var(:process))","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(:process) is useful when your stop rule depends on process-level state.","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"In Until/RepeatOrUntil, this function is a stop condition (true => stop, false => continue).","category":"page"},{"location":"user/vars/","page":"Vars (Var Selectors)","title":"Vars (Var Selectors)","text":"Var(...) is also the selector syntax used by interactive refs returned from view(context, Var(...)). See Interactive Contexts.","category":"page"},{"location":"user/inputs_overrides/#inputs_overrides_user","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Initialization specs and runtime inputs solve different problems.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init(...) provides values used while building persistent context.\nOverride(...) force-replaces initialized persistent context values.\nDSL @input declares per-run values supplied as run(...; kwargs...).","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Input(...) is still accepted as a compatibility alias for Init(...).","category":"page"},{"location":"user/inputs_overrides/#Init-and-Override-Specs","page":"Init, Overrides, and Runtime Inputs","title":"Init and Override Specs","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init and Override target one algorithm or state. Use the same reference style you used when adding that target to the composition: the type, the saved instance, a saved Unique(...) value, or an explicit symbol key.","category":"page"},{"location":"user/inputs_overrides/#API","page":"Init, Overrides, and Runtime Inputs","title":"API","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init(target; name = value, ...)\nOverride(target; name = value, ...)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Pair syntax is also accepted:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init(target, :name => value)\nOverride(target, :name => value)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Targets are resolved through the composed algorithm registry: the table of registered algorithms and states for the final process. After resolving, the target namespace is stored in the spec type and the matched registry entry is kept as ref for display and inspection.","category":"page"},{"location":"user/inputs_overrides/#When-They-Apply","page":"Init, Overrides, and Runtime Inputs","title":"When They Apply","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"init(la, specs...) applies persistent setup in this order:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init specs are merged into target subcontexts.\ninit(...) executes.\nOverride specs are merged after init.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"So:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Init is for values needed during initialization.\nOverride force-replaces initialized values.","category":"page"},{"location":"user/inputs_overrides/#Stored-Lifecycle-Specs","page":"Init, Overrides, and Runtime Inputs","title":"Stored Lifecycle Specs","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Initialized loop algorithms store their Init and Override specs. Calling init(la) again replays the stored specs and rebuilds the full persistent context.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Passed specs override stored specs per target:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"initialized = init(algo, Init(Walker; dt = 0.01))\nupdated = init(initialized, Init(Walker; dt = 0.02))","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"partialinit(la, specs...) rebuilds only the targeted algorithms or states:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"la = partialinit(la, Init(Walker; dt = 0.02))","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Both init and partialinit return a loop algorithm. Callers should use the returned value because the concrete context type may change.","category":"page"},{"location":"user/inputs_overrides/#Example","page":"Init, Overrides, and Runtime Inputs","title":"Example","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"algo = CompositeAlgorithm(Walker, InsertNoise, (1, 2))\n\np = Process(\n    algo,\n    Init(Walker; dt = 0.01),\n    Override(InsertNoise; seed = 1234),\n    repeats = 100,\n)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Use repeats = 100 for a fixed number of process loop iterations, or lifetime = Repeat(100) if you want to pass the lifetime object explicitly.","category":"page"},{"location":"user/inputs_overrides/#Targeting-and-Identity","page":"Init, Overrides, and Runtime Inputs","title":"Targeting and Identity","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"When choosing targets, use the same references you used in composition.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"For exact patterns and examples, see Referencing Algorithms.","category":"page"},{"location":"user/inputs_overrides/#Runtime-@input","page":"Init, Overrides, and Runtime Inputs","title":"Runtime @input","text":"","category":"section"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Runtime inputs are declared on a @CompositeAlgorithm or @Routine with @input. They are passed as keyword arguments to run, validated before loop execution, and merged into the transient ProcessContext._input field for that run only.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"algo = @CompositeAlgorithm begin\n    @state energy = 0.0\n    @input temperature::AbstractFloat\n    @input sweep = 1\n\n    step = metropolis(energy, temperature; sweep = sweep)\nend\n\nla = init(resolve(algo))\nla = run(la; temperature = 2.0)","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Runtime inputs are not stored in the loop algorithm. After the run finishes, the stored persistent context excludes runtime _input values.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Input declarations support:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"@input required_name\n@input typed_name::AbstractFloat\n@input defaulted_name = 1","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Rules:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"Required inputs must be passed to run.\nUnknown runtime keyword arguments are rejected.\nTyped inputs are checked with isa.\nDefaults are used when defaulted inputs are omitted.","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"For a Process, pass the same runtime inputs to run:","category":"page"},{"location":"user/inputs_overrides/","page":"Init, Overrides, and Runtime Inputs","title":"Init, Overrides, and Runtime Inputs","text":"p = Process(algo; repeats = 100)\nrun(p; temperature = 2.0)","category":"page"},{"location":"user/init_analysis/#init_analysis_user","page":"Init Analysis","title":"Init Analysis","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"ContextAnalyser is a lightweight, best-effort tool for discovering which values an entity's init and step! methods try to read.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"It is meant for exploratory analysis, not for exact validation. When an init path eventually errors because a missing value turned into nothing, analysis stops for that path and only the accesses up to that point are recorded.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use it when you are not sure which Input(...), Route(...), or Share(...) values an algorithm needs. The analyzer runs your hooks with a recording context instead of a normal runtime context.","category":"page"},{"location":"user/init_analysis/#Loading-It","page":"Init Analysis","title":"Loading It","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The analyzer lives in src/ContextAnalyzer/ContextAnalyzer.jl and is currently opt-in.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Load it into the module with:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"using Processes\nBase.include(Processes, joinpath(dirname(pathof(Processes)), \"ContextAnalyzer\", \"ContextAnalyzer.jl\"))","category":"page"},{"location":"user/init_analysis/#Running-Analysis","page":"Init Analysis","title":"Running Analysis","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use analyse_inits on a loop algorithm:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_inits(comp)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"This first builds a mock loop algorithm from the resolved one, with all repeats and intervals normalized to 1. It then creates analyzer views with view(...) and runs each flattened init inside a try block.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The analyzer records:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"which registered context entries were opened,\nwhich names each entry requested through context.x, get(context, :x, default), haskey(context, :x), or indexing,\na compact count of captured errors,\nstored per-view inputs that were seeded or produced during successful init calls.","category":"page"},{"location":"user/init_analysis/#Analysing-Steps","page":"Init Analysis","title":"Analysing Steps","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use analyse_steps when you want to probe runtime reads as well:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_steps(comp)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"By default this first runs the init analysis pass and then executes each flattened step-capable leaf once from that mock loop algorithm.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"You can disable the init pass when you already have enough seeded state:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_steps(comp; init = false, inputs = (; ...))","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Step analysis is still best-effort. It is most useful for discovering direct reads from the view. It does not try to perfectly reproduce every runtime routing/share writeback case.","category":"page"},{"location":"user/init_analysis/#Seeding-Inputs","page":"Init Analysis","title":"Seeding Inputs","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"You can pass per-view inputs with the inputs keyword:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"analysis = Processes.analyse_inits(\n    comp;\n    inputs = (;\n        CaptureSeed_1 = (; seed = 4, scale = 2.0),\n        DirectContextRead_1 = (; noise = 8.0),\n    ),\n)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"These inputs are keyed by the registered context names, such as :CaptureSeed_1.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Within a view:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"haskey(context, :x) returns true when x was seeded for that view,\nget(context, :x, default) returns the seeded value,\ncontext.x returns the seeded value,\nsuccessful init and step! return values are merged back into the analyzer's stored inputs.","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"That makes iterative analysis possible: seed what you already know, run analysis, inspect what is still requested, then rerun with more inputs in place.","category":"page"},{"location":"user/init_analysis/#Reading-Results","page":"Init Analysis","title":"Reading Results","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The default display is intentionally compact:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"println(analysis)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Use these helpers for programmatic access:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Processes.requested_inputs(analysis)\nProcesses.stored_inputs(analysis)\nanalysis.memory.errors","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"requested_inputs(analysis) returns a dictionary of:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"view_key => Vector{Symbol}","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"showing which symbols that view requested during analysis.","category":"page"},{"location":"user/init_analysis/#Printing-Events","page":"Init Analysis","title":"Printing Events","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Event traces are not printed by default. Print them explicitly with:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Processes.printevents(analysis)","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"This prints the recorded view, getproperty, get, haskey, and getindex events in order.","category":"page"},{"location":"user/init_analysis/#Forms-That-Analyse-Well","page":"Init Analysis","title":"Forms That Analyse Well","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"The analyzer only sees what goes through the context/view surface. These forms work best:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"required reads through context.x or destructuring like (; x, y) = context\noptional reads through get(context, :x, default)\nexplicit presence checks through haskey(context, :x)\nexplicit indexed reads like context[:OtherAlgo_1] or context[algo_ref]\n@ProcessAlgorithm ... @inputs((; ...)) for init-only requirements\nstep! methods that return plain NamedTuples with stable output names","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"These forms are harder to analyse accurately:","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"dynamically constructed property names or keys\nreads from globals, closures, captured mutable state, files, or random external sources\ncontrol flow where a missing value quickly becomes nothing and errors before later accesses happen\nstep paths that depend on exact routed writeback behavior across subcontexts","category":"page"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"If you want better analysis results, prefer direct view reads over indirect lookup logic.","category":"page"},{"location":"user/init_analysis/#Typical-Workflow","page":"Init Analysis","title":"Typical Workflow","text":"","category":"section"},{"location":"user/init_analysis/","page":"Init Analysis","title":"Init Analysis","text":"Run analyse_inits(comp) once.\nInspect Processes.requested_inputs(analysis).\nSeed the next round with analyse_inits(comp; inputs = ...).\nRepeat until the interesting init paths stop asking for unknown values.","category":"page"},{"location":"user/running/#running_user","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"This page covers the normal runtime flow: create a Process, run it, wait for it, and inspect the result.","category":"page"},{"location":"user/running/#Create-a-Process","page":"Running, Wait, Fetch","title":"Create a Process","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"p = Process(algo, Init(...), Override(...); repeats = 1_000)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Process(...) resolves the loop algorithm when needed, runs the lifecycle init path, and stores the algorithm plus its current context on the process.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Persistent context is built from Init(...), Override(...), @state, routes, shares, and managed state. Runtime @input values are not stored at construction time.","category":"page"},{"location":"user/running/#Run-and-Resume","page":"Running, Wait, Fetch","title":"Run and Resume","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"run(p)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"run(p) starts the process loop task. If the process was paused, run(p) resumes the suspended runtime context; new runtime inputs, init specs, and lifetime changes are rejected during resume.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"If the loop algorithm declares runtime @input values, pass them as run keywords:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"run(p; temperature = 2.0, sweep = 10)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"The keywords are converted to a NamedTuple, validated against the algorithm's runtime input declarations, and merged into ProcessContext._input only for that loop run. Finished processes strip runtime-only fields before storing their persistent context. A paused process may keep its live runtime context internally so it can resume.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Initialized loop algorithms can also be run directly:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"la = init(resolve(algo), Init(MyAlgo; buffer = Float64[]))\nla = run(la; temperature = 2.0)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"The returned loop algorithm contains the next persistent context. Use the returned value; runtime inputs are stripped before the context is stored back on the returned algorithm.","category":"page"},{"location":"user/running/#Lifetime","page":"Running, Wait, Fetch","title":"Lifetime","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Stop behavior can be given either as a simple repeat count or as a lifetime object:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"repeats = 1000 -> run a fixed number of iterations.\nomitted -> default lifetime behavior for that algorithm type.\nadvanced: lifetime = Repeat(...), lifetime = Indefinite(), lifetime = Until(...), lifetime = RepeatOrUntil(...).","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"See Lifetime for full details. For selector syntax used in Until, see Vars (Var Selectors).","category":"page"},{"location":"user/running/#Control-Operations","page":"Running, Wait, Fetch","title":"Control Operations","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"pause(p): stop loop while keeping resumable state.\nrun(p): start a new task or resume after pause.\nclose(p): stop the process and collect the final task result into the stored process context.\nreinit(p): compatibility helper that pauses, reruns lifecycle init, and runs again.\npartialinit(la, specs...): rebuild only the targeted algorithms or states on an initialized loop algorithm.","category":"page"},{"location":"user/running/#Waiting-and-Fetching","page":"Running, Wait, Fetch","title":"Waiting and Fetching","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"wait(p): block until task completes.\nfetch(p): return the task return value.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"In practice:","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"use wait(p) when you just want to block until completion,\nuse fetch(p) when you want the task's return value,\nuse context(p) for the stored persistent process context,\nuse getcontext(p) when you want that context with the process injected into globals.","category":"page"},{"location":"user/running/#Status-Helpers","page":"Running, Wait, Fetch","title":"Status Helpers","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"isrunning(p)\nispaused(p)\nisdone(p)\nisidle(p)","category":"page"},{"location":"user/running/#Inline-Process","page":"Running, Wait, Fetch","title":"Inline Process","text":"","category":"section"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"Use InlineProcess when you want synchronous execution without a separate process task. It accepts the same positional Init(...)/Input(...) and Override(...) arguments as Process(...):","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"ip = InlineProcess(algo, Init(...), Override(...); repeats = 10_000)\nrun(ip)","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"InlineProcess also accepts lifetime = 10_000 and converts it to a repeat count. For Process, use repeats = 10_000 or lifetime = Repeat(10_000). Unlike Process, InlineProcess stores a context that can be absorbed back into an algorithm, so runtime-only fields such as :_input and process are stripped after the loop. Like finished Process runs, this means the stored context is the persistent context shape rather than the transient loop context.","category":"page"},{"location":"user/running/","page":"Running, Wait, Fetch","title":"Running, Wait, Fetch","text":"If you need buffered external updates to context variables, see Interactive Contexts.","category":"page"},{"location":"compile_optimization_notes/#Compile-Optimization-Notes","page":"Compile Optimization Notes","title":"Compile Optimization Notes","text":"","category":"section"},{"location":"compile_optimization_notes/","page":"Compile Optimization Notes","title":"Compile Optimization Notes","text":"Potential next targets, in the order they should be investigated:","category":"page"},{"location":"compile_optimization_notes/","page":"Compile Optimization Notes","title":"Compile Optimization Notes","text":"Reduce the remaining generated merge/context code. The latest profile still shows merge_into_subcontext_*, merge_into_subcontexts, generated ProcessContext construction, and generated SubContextView getproperty in the first-run compile path. The single-name lookup already removed the biggest get_all_locations cost; the next step should be smaller emitted expressions, not more background tasks.\nCheck whether get_all_locations is still needed in normal non-error paths. It should now be mostly property enumeration, explicit keys/propertynames, and error reporting. If profiles show it from normal execution again, trace the exact caller before adding a cache.\nCheck first-step and steady-step duplication. Repeat loops compile an unstable first step and a stable steady loop. For algorithms whose context type cannot grow, there may be a way to skip or shrink the unstable generated path.\nIsolate context init merge cost. Lifecycle init now resolves Init/Override specs and stores them on the initialized loop algorithm. The remaining cost is probably applying named specs through generated context merge/init code. Benchmark init(la) with and without specs separately.\nCache resolved algorithm metadata by concrete loop algorithm type. Registry setup, flat funcs/states/multipliers, and share/route resolution are mostly type-structural. This must account for mutable algorithm instances and options that are value-dependent.\nSplit generated step compilation only where the semantic boundary is clear. Avoid random helper churn. Candidate boundaries are route lookup, context view access, and merge planning. The goal is to let shared structural parts compile once while keeping the final concrete setter fast.\nBenchmark copyprocess and context copy cost separately. Learning workloads copy template contexts often. Measure whether deepcopy(context) or fresh structural init is more expensive for realistic contexts.\nKeep Process first-entry context concrete but resumed context broad. The stored LoopAlgorithm context is already concrete and should remain the first-run source. Process.runtime_context is deliberately Union{Nothing, ProcessContext} for resumed/replaced contexts; do not add a Process{F,C} parameter again unless a new profile shows a real win.\nKeep empty tuple paths specialized. Empty inputs, overrides, options, shares, and routes are common and should avoid generic filtering/merging.\nKeep the compile benchmark suite current.  Report package load separately from stage timings, and keep cold and warm  stage measurements separate.\nRevisit background precompile only from values close to first use.  Process-constructor loop precompile has been useful enough to keep.  LoopAlgorithm-constructor metadata precompile was too early and contended  with construction/input resolution. Any new background precompile should be  measured against total construct-to-first-run time, not construction alone.\nAvoid precompile hooks that only move work earlier.  Constructor loop precompile should target exact first-run signatures.  Resolve-time precompile and broad metadata precompile have both been tested  and made immediate TTFP worse. The next useful precompile work is probably  reducing the amount of generated user-algorithm-specific code, not launching  more tasks earlier.","category":"page"},{"location":"compile_optimization_attempts/#Compile-Optimization-Attempts","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"This file records compile-latency experiments so failed paths are not repeated.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Some older entries below mention TaskData. That type has been removed from the active lifecycle; those notes are retained as historical compile-latency context only.","category":"page"},{"location":"compile_optimization_attempts/#Kept-Changes","page":"Compile Optimization Attempts","title":"Kept Changes","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Captured concrete loop algorithm types in helper signatures. This replaced several Type{<:T} method arguments with Type{Concrete} where Concrete <: T when the method reads the exact type.\nAdded constructor-time ProcessManager precompile scheduling. The hook runs after manager construction and targets concrete manager, slot, and job types.\nKept constructor-time Process loop precompile scheduling. This is close enough to the first run call to reduce first-run latency without precompiling broad LoopAlgorithm metadata paths too early. The precompile signature now targets the actual non-generated loop method: loop(process, algo, context, lifetime, inputs, Resuming{false}, NonGenerated). The previous signature omitted inputs and Resuming, so it aimed at a wrapper shape that did not match the first-run call.\nMoved process loop precompile helpers to ProcessPrecompile.jl and removed lock/dedup task bookkeeping. The construction hook now schedules a plain best-effort precompile task, and first run no longer waits on or coordinates a global precompile task registry. This reduced nearby constructor overhead and made the profile easier to read.\nAdded a narrow SimpleAlgo(single_algorithm) construction fast path. The common one-algorithm case now builds the simple LoopAlgorithm directly instead of going through the full CompositeAlgorithm parser and flatten_comp_funcs. intervals(::SimpleAlgo) still returns Interval(1) values so existing multiplier code sees the same shape.\nReduced generation-time work in context constructors and merges. Generated helpers now use simple static loops instead of closure-based all/filter/findfirst scans, and _merge_into_globals constructs a ProcessContext directly instead of going through the generic setfield generated helper.\nAdded single-name SubContextView location lookup for generated read and merge paths. Normal getproperty(view, Val(name)), haskey(view, Val(name)), and stablemerge/unstablemerge planning no longer build the full location table just to resolve one name. The full get_all_locations path remains for property enumeration and error reporting.\nAvoided empty process setup work. Empty input/override construction now skips a throwaway context build, and empty initcontext paths avoid vararg filtering.\nMoved setfield debug rendering out of generated-function generation. Large debug strings are now built only on the error path.\nMade input/override resolution require a resolved algorithm. prepare_process_constructor resolves the normalized algorithm before resolving inputs or overrides. resolve_process_inputs_overrides now reads the registry from that resolved algorithm and errors when called directly with an unresolved algorithm. This is mostly a contract cleanup; measured compile latency was neutral against the same benchmark using an already-resolved algorithm.\nFused single-algorithm resolve registry build with algorithm keying. The single-argument path now uses the keyed algorithm returned while adding algorithms to the registry instead of building a registry and then doing a second registry lookup pass through update_keys. Multi-algorithm resolve still uses the shared-registry path.\nBound concrete value argument types in the resolve/materialization helpers. Changing signatures such as la::LoopAlgorithm and registry::NameSpaceRegistry to la::LA where LA<:LoopAlgorithm and registry::R where R<:NameSpaceRegistry improved the full process benchmark after the fused resolve change. This is not only useful for Type arguments; it can help value arguments too.\nAdded narrow lifecycle/input resolution fast paths. init(la, Input(...), Override(...)) now resolves specs through typed methods for empty, already-named, and raw Init/Override tuples. Context construction receives the already-resolved lifecycle-stripped algorithm, so it does not resolve again. The public input/override resolver also has a typed all-Input/Override path while preserving the old generic fallback.\nInlined only small setup-path accessors and wrappers that improved the simple compile benchmark. The retained inline hints are on the resolve preparation chain, lifecycle constructor helpers, input/override accessors, and generic LoopAlgorithm interface accessors.\nKept the normal first-entry Process context on the concrete algorithm path. Process.runtime_context now starts as nothing; makeloop! reads the stored algorithm context for the first run and only falls back to runtime_context after external context replacement or a returned runtime context. This removes the runtime_context::Any leak from the first-entry loop path without changing the public context(process) behavior after a run. The runtime field itself is now Union{Nothing, ProcessContext} rather than Any, so resumed contexts are intentionally abstract only at the ProcessContext level.\nKept concrete stored contexts on initialized LoopAlgorithm values. CompositeAlgorithm and Routine both store context::C, where C is a type parameter. For an initialized algorithm, fieldtype(typeof(la), :context) === typeof(getstoredcontext(la)) holds, and the first-entry process path through _typed_runtime_context(process) infers the exact ProcessContext{...} type.\nExtended the PrecompileTools workload for the managed @ProcessAlgorithm normal Process path. The workload now covers SimpleAlgo(_ProcessPrecompileManaged), typed Input/Override resolution, lifecycle init(...; lifetime = Repeat(1)), Process(...), first run, and construction from an already initialized algorithm. This covers the package-side version of the compile benchmark's managed lifecycle path. It cannot remove compilation of user-defined Main.@ProcessAlgorithm generated methods, but it does precompile the package helper methods those generated algorithms call.\nAdded narrow @nospecialize barriers on Base.wait(::Process) and Base.fetch(::Process). These methods only touch p.task or p.lastresult, so they do not need a separate specialization for every full Process{CompositeAlgorithm{...}} type. A trace-compile pass on the simple TTFP script dropped from about 137 lines to about 116 lines after the exact loop precompile and wait/fetch barriers.","category":"page"},{"location":"compile_optimization_attempts/#Reverted-Or-Rejected","page":"Compile Optimization Attempts","title":"Reverted Or Rejected","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"@nospecialize on process precompile helpers. Julia accepts both formal-argument and statement-position @nospecialize, but the tested changes made latency noisier or worse.\nGenerated location caching for subcontext views. The idea was to cache location computation in generated helpers. In the tested pattern it did not improve the target benchmark.\nRefactoring stablemerge/unstablemerge merge planning. Several versions using grouped plans and helper functions were neutral or slower.\nStructural helpers for _global_context_type and related loop precompile signatures. They passed tests but worsened construction/first-run latency.\nReusing the input-resolution ProcessContext through a public TaskData keyword option. This avoided one duplicate context build, but introduced a new constructor specialization path and did not produce a stable win.\nReusing the input-resolution ProcessContext through a narrow internal Process constructor path. This avoided one duplicate context build for Process(algo, Input(...), Override(...)), but did not improve the compile-latency benchmark. The first call is dominated by compilation of resolution, merge, init, and run paths; after compilation, warm process construction is already small enough that the saved context build is below benchmark noise. This was removed to keep the constructor path simpler.\nSplitting TaskData into a typed positional internal helper. This was meant to avoid keyword dispatch in Process construction. It increased cold-stage latency in the compile benchmark.\nAdding type parameters directly to the public TaskData keyword constructor. This also worsened compile-facing benchmark numbers and was reverted.\nConstructor-time LoopAlgorithm metadata precompile. Immediate scheduling made nearby construction and input-resolution stages contend with background compilation. Adding an arbitrary sleep moved the contention but did not reliably improve immediate time-to-first-process-run. The hook, lock, type set, delay constant, and metadata precompile helper were removed.\nSplitting setup_registry into an add_loopalgorithm_to_registry helper. Both a fully specialized helper and a variant with @nospecialize on the loop algorithm were tested. The split made cold construction/first-run latency worse and also hurt warmed process-loop timing, so the original single-body registry setup remains preferable.\nAdding a @noinline unresolved-resolve boundary. The goal was to stop Process construction from compiling through the full resolve path. In practice it made first-run and warmed process-loop timing worse, which suggests the resolved algorithm type information is still useful to the later loop path.\nAdding Base.@constprop :none to setup_registry. This was meant to reduce caller-side compile work without changing semantics, but it worsened warmed loop timing and was removed.\nRewriting only resolve(la::LoopAlgorithm) as resolve(la::LA) where {LA<:LoopAlgorithm} before the fused resolve change. Isolated to the old resolve implementation, this did not improve the compile benchmark. After the fused single-resolve implementation, applying the pattern consistently to the resolve helper chain did improve the full process benchmark.\nBroad @inline pass over Process utility helpers. Inlining one-hop helpers around process state, runtime, precompile signatures, and loop scheduling did not improve direct time to first process run and made staged lifecycle/hot timings noisier, so it was reverted.\nBroad @inline pass over CompositeAlgorithm and Routine accessors. This worsened direct time to first process run substantially in the simple benchmark, with samples around 679 / 721 / 826 ms, so it was reverted. The useful inline hints are much narrower.\nAdding the process context type as a second Process{F,C} parameter. This made first-entry context access infer, but it also made the process type larger and worsened direct time to first run. The retained version keeps Process{F} and reads the typed context from getstoredcontext(getalgo(p)) while runtime_context is empty.\nType-level replacement for _global_context_type. A generated helper computed the context type for _merge_into_globals(context, (; process = p)) without doing the merge. It made staged Process construction slower, so the value-based implementation was restored.\nStripping :_input and :process before storing a finished Process context. This kept the typed first-entry path available after completion, but it changed the public context(process) result. Existing runtime-input tests expect those transient entries to remain visible after run/wait, so the stripping was reverted for Process.\nForcing context(process) to always return the stored loop algorithm context. This was tested as a temporary diagnostic to check whether the abstract runtime_context branch explained TTFP. It did not. With 8 Julia threads, direct time to first process run stayed at about 546-549 ms, matching the restored getter. The patch was reverted.\nAsync resolve(typeof(la)) precompile immediately after loop algorithm construction. A narrow manual test still worsened direct TTFP: with an explicit wait it was about 560-569 ms, and without waiting it was about 566-569 ms, compared with a current baseline around 547-552 ms. This confirms that resolve-time precompile is still too early for the immediate construct-and-run path.\nDisabling constructor loop precompile. This was neutral to slightly worse for direct TTFP and moved work from Process construction into first run. The constructor precompile remains useful, but only when it targets the exact loop signature.\n@nospecialize on run!(::Process). This wrapper looked like an easy compile barrier, but it regressed direct TTFP to about 571-578 ms, so it was reverted. run! should keep the concrete process type so the call into run/makeloop! remains well inferred.","category":"page"},{"location":"compile_optimization_attempts/#Current-Benchmark-Notes","page":"Compile Optimization Attempts","title":"Current Benchmark Notes","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"After the latest profiling pass on the simple managed @ProcessAlgorithm microbench with 8 Julia threads, direct construct-to-first-run timings were about 295 / 303 / 298 ms. Before these local changes the same path was around 516-529 ms; after only the SimpleAlgo fast path it was around 434-444 ms.\nThe main wins came from avoiding the full parser for single SimpleAlgo, not building full location tables for one-name view access/merge planning, and removing generic setfield from _merge_into_globals.\nmanual tests/ProcessHotLoopBenchmark.jl checks normal hot-loop runtime. Recent larger runs did not show a normal Process hot-loop regression against clean HEAD.\nmanual tests/ProcessCompileLatencyBenchmark.jl should break compile-facing work into algorithm construction, resolve, lifecycle init, Process constructor, first run, and warmed hot runs.\nmanual tests/ProcessResolveBenchmark.jl measures fresh construction, resolve, already-resolved resolve, initcontext, Process construction, first run, and warmed fresh-resolve throughput for simple, routed, shared, and nested algorithms.\nThe current benchmark should be refreshed against the lifecycle-init path. Metadata reuse should stay on narrow internal paths.\nCurrent lifecycle fast-path benchmark on 8 Julia threads: direct time to first process run is about 545-552 ms across cold Julia processes after the lifecycle/input refactor and first-entry context cleanup. Temporarily bypassing runtime_context entirely did not improve this number. The staged compile benchmark still shows the cold cost mainly in algorithm construction, Process construction, and first run; warmed construction and warmed first run are small.","category":"page"},{"location":"compile_optimization_attempts/#LoopAlgorithm-Stored-Context-Check","page":"Compile Optimization Attempts","title":"LoopAlgorithm Stored Context Check","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The initialized loop algorithm context is typed correctly. A small diagnostic using a one-step CompositeAlgorithm showed:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"typeof(la).parameters[6] is the concrete stored context type.\nfieldtype(typeof(la), :context) === typeof(getstoredcontext(la)).\ngetstoredcontext(la) infers the concrete ProcessContext{...}.\n_typed_runtime_context(process) infers the same concrete ProcessContext{...} before the process has stored a returned runtime context.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"This means the remaining first-run compile cost is not caused by the stored LoopAlgorithm context being abstract. The intentionally abstract point is only the mutable Process.runtime_context after a runtime context has been stored or externally replaced.","category":"page"},{"location":"compile_optimization_attempts/#SnoopCompile-Pass","page":"Compile Optimization Attempts","title":"SnoopCompile Pass","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Ran a temporary-environment SnoopCompile pass with SnoopCompileCore.@snoop_inference on the compile benchmark workload. The project dependency files were not changed.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Important exclusive inference-time signals from the small benchmark:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"step! generated by @ProcessAlgorithm: about 55 ms.\nget_all_locations(::Type{<:SubContextView}): about 51 ms accumulated.\nBase.getproperty(::SubContextView, ::Val): about 44 ms accumulated.\n_merge_into_globals: about 35 ms accumulated.\nmerge_into_subcontext_rebuild: about 28 ms accumulated.\nmerge(::SubContextView, ::NamedTuple): about 25 ms.\ninit generated by @ProcessAlgorithm: about 25 ms.\nsetup_registry: about 19 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Important inclusive paths:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"resolve(::CompositeAlgorithm): about 207 ms, mostly through registry setup.\nloop(::Process, ::CompositeAlgorithm, ::ProcessContext, ::Repeat, ::NonGenerated): about 122 ms.\nlegacy initcontext(::TaskData{... inputs/overrides ...}): about 92 ms.\nProcess(...; repeats=1): about 87 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The pass also showed inference under background precompile tasks launched from Process.jl. Future SnoopCompile runs should either disable those tasks or run a separate pass specifically for the precompile pipeline, otherwise normal workload inference and background precompile inference are mixed together.","category":"page"},{"location":"compile_optimization_attempts/#LoopAlgorithm-Metadata-Precompile","page":"Compile Optimization Attempts","title":"LoopAlgorithm Metadata Precompile","text":"","category":"section"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The first SnoopCompile pass showed background metadata precompile tasks mixed into normal first-call inference. The compile benchmark confirmed this was not just a measurement artifact: launching metadata precompile immediately from LoopAlgorithm construction made the next constructor stages contend with those tasks.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Measured cold-stage comparison on the simple compile benchmark:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Immediate background precompile: algo construction ~= 106 ms, input resolution ~= 118 ms, Process constructor ~= 63 ms, first run ~= 137 ms.\nDisabled metadata precompile: algo construction ~= 105 ms, input resolution ~= 30 ms, Process constructor ~= 61 ms, first run ~= 151 ms.\nDelayed metadata precompile by 0.2s: algo construction ~= 106 ms, input resolution ~= 27 ms, Process constructor ~= 54 ms, first run ~= 141 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"Later measurements showed the best immediate construct-to-first-run path came from removing the LoopAlgorithm constructor metadata precompile entirely while keeping the Process constructor loop precompile:","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"No LoopAlgorithm metadata precompile: algo construction ~= 87-90 ms, input resolution ~= 26-33 ms, Process constructor ~= 53-55 ms, first run ~= 123-134 ms.","category":"page"},{"location":"compile_optimization_attempts/","page":"Compile Optimization Attempts","title":"Compile Optimization Attempts","text":"The conclusion is that metadata precompile from LoopAlgorithm construction is too early for this workload. It either contends with input resolution or, when delayed, is less useful for the immediate first run. The retained precompile path is the Process constructor loop precompile, which is closer to the actual code that will run.","category":"page"},{"location":"user/value_semantics/#value_semantics_user","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Most users only need one rule here:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"if you use the same algorithm type once, plain types or instances are fine;\nif you need multiple logically distinct instances of the same algorithm, use Unique(...) and keep the returned value around.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Unique exists to give one inserted algorithm a guaranteed separate identity in the registry and therefore a separate subcontext in the process context.","category":"page"},{"location":"user/value_semantics/#When-You-Need-Unique","page":"Value Semantics and Unique","title":"When You Need Unique","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"You usually need Unique(...) when you want more than one copy of the same algorithm in a composition and you need to target them separately in:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Route(...)\nShare(...)\nInput(...)\nOverride(...)\nVar(...)","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Example:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"producer_a = Producer()\nproducer_b = Unique(Producer())\nconsumer = Consumer()\n\nalgo = CompositeAlgorithm(\n    producer_a, producer_b, consumer,\n    (1, 1, 1),\n    Route(producer_b => consumer, :value),\n)","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Without Unique, repeated equal immutable values or repeated type-based entries can be treated as the same logical identity.","category":"page"},{"location":"user/value_semantics/#Matching-Rules","page":"Value Semantics and Unique","title":"Matching Rules","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"For process entities (ProcessAlgorithm/ProcessState), the current matching rules are:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"an immutable instance that Julia can store directly in a type parameter matches by value,\na mutable or otherwise non-direct instance matches by object identity,\na type matches by that type.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"So Fib() and Fib are different identities.","category":"page"},{"location":"user/value_semantics/#Why-Instance-Lookup-Can-Be-Surprising","page":"Value Semantics and Unique","title":"Why Instance Lookup Can Be Surprising","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"The practical rule is: reuse the same reference you inserted.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Fresh values can be surprising:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"a fresh immutable value can match an equal inserted immutable value,\na fresh mutable value is a different object and normally does not match the inserted one,\na type such as Fib targets the type-based entry, not an instance entry like Fib().","category":"page"},{"location":"user/value_semantics/#Unique","page":"Value Semantics and Unique","title":"Unique","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"Unique(x) wraps x in IdentifiableAlgo with a UUID identity.","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"That gives a guaranteed separate registry identity and thus separate subcontext key, even when:","category":"page"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"two wrapped values are otherwise equal,\nthey were added by the same type,\nor they are hard to distinguish by normal Julia equality.","category":"page"},{"location":"user/value_semantics/#Recommended-Patterns","page":"Value Semantics and Unique","title":"Recommended Patterns","text":"","category":"section"},{"location":"user/value_semantics/","page":"Value Semantics and Unique","title":"Value Semantics and Unique","text":"One logical instance per type: plain type or instance is fine.\nMultiple logical instances of same algorithm: use Unique(...) and keep references.\nInputs/routes/shares for those distinct instances: reference the same Unique values you inserted into composition.","category":"page"},{"location":"user/referencing_algorithms/#referencing_algorithms_user","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Use this page whenever you need to point to a specific algorithm in:","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Route(...)\nShare(...)\nInput(...)\nOverride(...)","category":"page"},{"location":"user/referencing_algorithms/#One-Rule","page":"Referencing Algorithms","title":"One Rule","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Reference algorithms the same way you inserted them into the composition.","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Added by type -> reference by that type.\nAdded by saved instance variable -> reference by that same variable.\nAdded by Unique(...) -> reference by that same saved unique variable.","category":"page"},{"location":"user/referencing_algorithms/#Pattern-1:-Added-by-Type","page":"Referencing Algorithms","title":"Pattern 1: Added by Type","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"struct Producer <: ProcessAlgorithm end\nstruct Consumer <: ProcessAlgorithm end\n\nalgo = CompositeAlgorithm(\n    Producer, Consumer,\n    (1, 1),\n    Route(Producer => Consumer, :value),\n)","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Use Producer and Consumer again when targeting these algorithms.","category":"page"},{"location":"user/referencing_algorithms/#Pattern-2:-Added-by-Instance","page":"Referencing Algorithms","title":"Pattern 2: Added by Instance","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"producer = Producer()\nconsumer = Consumer()\n\nalgo = CompositeAlgorithm(\n    producer, consumer,\n    (1, 1),\n    Route(producer => consumer, :value),\n)","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Use producer and consumer again, not fresh Producer() calls.","category":"page"},{"location":"user/referencing_algorithms/#Pattern-3:-Added-with-Unique","page":"Referencing Algorithms","title":"Pattern 3: Added with Unique","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"producer_a = Producer()\nproducer_b = Unique(Producer())\nconsumer = Consumer()\n\nalgo = CompositeAlgorithm(\n    producer_a, producer_b, consumer,\n    (1, 1, 1),\n    Route(producer_b => consumer, :value),\n)","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"producer_b is a distinct identity. Keep that variable and reuse it anywhere you need to target that exact algorithm.","category":"page"},{"location":"user/referencing_algorithms/#Common-Mistake","page":"Referencing Algorithms","title":"Common Mistake","text":"","category":"section"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Do not create a new object in Route/Share/Input/Override unless that exact object was inserted in the composition.","category":"page"},{"location":"user/referencing_algorithms/","page":"Referencing Algorithms","title":"Referencing Algorithms","text":"Some immutable objects can match by equal value, but relying on that makes code harder to read. Reusing the original reference is the clearest rule.","category":"page"},{"location":"internals/registry/#registry_internals","page":"Registry","title":"Registry Internals","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"The registry layer is what assigns stable subcontext names to algorithms/states and makes value/type lookups predictable.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Core types:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"NameSpaceRegistry: top-level registry (src/Registry/StructDefs.jl).\nRegistryTypeEntry{T}: one partition per entry type (src/Registry/StructDefs.jl).\nIdentifiableAlgo{F,Id,...,Key}: wrapped process entity with identity and assigned context key (src/Identifiable/StructDef.jl).","category":"page"},{"location":"internals/registry/#1.-Type-Partitions-and-Matching","page":"Registry","title":"1. Type Partitions and Matching","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Entries are grouped by assign_entrytype(obj) (src/Registry/Traits.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Default entry type: the object's type wrapper.\nIdentifiableAlgo overrides this via registry_entrytype(::Type{<:IdentifiableAlgo{T}}) = T (src/Identifiable/IdentifiableAlgos.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Within each RegistryTypeEntry, matches use match_by (src/Matching.jl, src/ProcessEntities/Matching.jl):","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Process entity instance (Fib()): direct immutable instances match by value; other instances match by object identity.\nProcess entity type (Fib): matches by type (match_by(::Type{<:ProcessEntity}) = T).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"This is why instance-based and type-based registrations are distinct identities.","category":"page"},{"location":"internals/registry/#2.-Key-Assignment","page":"Registry","title":"2. Key Assignment","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"add(reg, obj, multiplier) (src/Registry/Registries.jl, src/Registry/TypeEntries.jl) does:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Find/create the correct RegistryTypeEntry.\nIf no match exists, create a key with Autokey (TypeName_index) and wrap as IdentifiableAlgo.\nIf a match exists, reuse the existing key and increase multiplier.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Key consequences:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Same value entered repeatedly: same key reused.\nSame type entered repeatedly: same key reused for that type identity.\nType-entered value vs value-entered value can still be different identities.\nThis stays true across nested CompositeAlgorithm/Routine trees because setup_registry flattens all entities into one registry pass before context creation.","category":"page"},{"location":"internals/registry/#3.-Unique-and-Distinguishability","page":"Registry","title":"3. Unique and Distinguishability","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Unique(f) builds an IdentifiableAlgo with a fresh UUID identity (src/Identifiable/StructDef.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"That gives a guaranteed distinct match identity even when the wrapped value is otherwise indistinguishable.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"This is the mechanism used when you need multiple logically separate instances of the same algorithm in one composition.","category":"page"},{"location":"internals/registry/#4.-Lookup-Behavior","page":"Registry","title":"4. Lookup Behavior","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"ProcessContext lookups by value/type eventually call registry getindex (src/Context/ProcessContexts.jl, src/Registry/Registries.jl).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"The registry also supports direct symbol-key lookup:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"reg[:Fib_1] returns the registered IdentifiableAlgo","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"That is the same key space used by:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"resolved[:Fib_1] on resolved loop algorithms\nctx[:Fib_1] on process contexts","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Important runtime detail in NameSpaceRegistry.getindex:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Type, direct immutable values, and AbstractIdentifiableAlgo values use the static lookup path.\nother values use the dynamic lookup table keyed by match_by(obj).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"So direct immutable instances can match equal values, while ordinary mutable instances match by object identity. Unique(...) gives an explicit fresh identity when the default rules are not what you want.","category":"page"},{"location":"internals/registry/#5.-Multipliers","page":"Registry","title":"5. Multipliers","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"Each registry entry tracks a multiplier (RegistryTypeEntry.multipliers).","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"For loop algorithms this is derived from composition structure (intervals/repeats), and is used by utilities such as processsizehint!/num_calls (src/Tools.jl).","category":"page"},{"location":"internals/registry/#6.-Order-Guarantees","page":"Registry","title":"6. Order Guarantees","text":"","category":"section"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"setup_registry adds:","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"ProcessStates first.\nThen flattened algorithms.","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"(see src/LoopAlgorithms/Setup.jl)","category":"page"},{"location":"internals/registry/","page":"Registry","title":"Registry","text":"That ordering controls init/cleanup traversal order through all_algos(registry).","category":"page"},{"location":"internals/process_pipeline/#process_pipeline_internals","page":"Process Pipeline","title":"Process Pipeline Internals","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"This page documents the runtime path from loop algorithm construction to loop execution.","category":"page"},{"location":"internals/process_pipeline/#1.-Construction","page":"Process Pipeline","title":"1. Construction","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Process(func, inputs_overrides...; repeats, lifetime, timeout) (src/Process.jl):","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Wrap bare ProcessAlgorithm as a one-child CompositeAlgorithm.\nNormalize stop behavior: repeats = n becomes Repeat(n), lifetime accepts Lifetime objects, and Routine defaults to Repeat(1) when no lifetime is provided.\nResolve the loop algorithm when needed.\nRun lifecycle init(algo, specs...; lifetime) unless an initialized context is already provided.\nStore the algorithm and its current runtime context on the process.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"There is no TaskData layer. The initialized loop algorithm carries the persistent context plus stored init/override specs. Process keeps its current context separately so pausing can preserve a suspended runtime context without rebaking it into the algorithm.","category":"page"},{"location":"internals/process_pipeline/#2.-Init-Phase","page":"Process Pipeline","title":"2. Init Phase","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"init(la::LoopAlgorithm, specs...) (src/LoopAlgorithms/RuntimeInputs.jl) applies:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Resolve Init/Override specs through the registry.\nMerge passed specs over stored specs per target.\nBuild a fresh persistent ProcessContext with algo and lifetime in _runtime.\nMerge Init values into target subcontexts.\nRun init(algo, input_context).\nMerge Override values after init.\nReturn a loop algorithm with stored context, inits, and overrides.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"For loop algorithms, init(::LoopAlgorithm, ::ProcessContext) iterates all registry entities in order (src/LoopAlgorithms/Init.jl).","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"partialinit(la, specs...) uses the same target resolution but only rebuilds the targeted subcontexts.","category":"page"},{"location":"internals/process_pipeline/#3.-Running","page":"Process Pipeline","title":"3. Running","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"run(p; kwargs...) (src/ProcessInteraction.jl) calls makeloop! (src/Process.jl).","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"makeloop!:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"validates runtime keyword arguments against the loop algorithm's @input metadata,\npasses the persistent context to loop,\npasses runtime inputs as a positional NamedTuple to loop,\nspawns the loop task.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"run(la::LoopAlgorithm; kwargs...) runs an initialized loop algorithm directly and returns a loop algorithm with the next persistent context.","category":"page"},{"location":"internals/process_pipeline/#4.-Loop-Bootstrap-and-Runtime-Inputs","page":"Process Pipeline","title":"4. Loop Bootstrap and Runtime Inputs","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"The loop wrappers in src/Loops.jl merge runtime inputs before the while/for loop:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"loop(process, algo, context, lifetime, inputs)","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"The loop injects process and lifetime into the transient _runtime field. An empty input tuple is a no-op. A non-empty tuple is merged into the transient ProcessContext._input field. The bootstrap/first step may change the transient context type. After bootstrap, steady-state steps must preserve context type.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Repeat and indefinite loops are defined in src/Loops.jl; generated loops live in src/GeneratedCode/GeneratedLoops.jl.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"High-level structure:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"before_while(process)\none unstable/bootstrap step\nrepeat/while body with stable step calls\ntick/index increments\nafter_while(process, algo, context, stored_context)","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Step bodies are produced by step!_expr (src/LoopAlgorithms/GeneratedStep.jl and src/Identifiable/Step.jl) so composite/routine structures can be unrolled and specialized to concrete algorithm/context types.","category":"page"},{"location":"internals/process_pipeline/#5.-Cleanup-Behavior","page":"Process Pipeline","title":"5. Cleanup Behavior","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"after_while (src/Loops.jl) does:","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"paused process: store the suspended runtime context as a side effect, but compute the task result from the stripped persistent context shape.\ninterrupted or indefinite: strip runtime-only fields before computing the task result.\nnatural finite completion: store cleanup(func, context) stripped back to persistent context shape, then compute the task result.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Finished Process, InlineProcess, and direct run(la::LoopAlgorithm) paths store contexts that may be absorbed back into an algorithm, so runtime-only fields such as _input, process, and lifetime are stripped. A paused Process may still keep the live runtime context internally so it can resume. For ordinary algorithms the task result is the stripped context. For FinalizedAlgorithm, the final function projects a result from that stripped context, so fetch(process) still returns the @finally value.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Paused processes resume through the normal loop path with a Resuming{true} entry trait. Fresh runs use Resuming{false}. This keeps the bootstrap decision in dispatch, so fresh runs infer the post-bootstrap context type and resumed runs infer the already-grown context type. New runtime inputs, init specs, and lifetime changes are rejected while resuming.","category":"page"},{"location":"internals/process_pipeline/#6.-Open-Discovery-Phase-Need","page":"Process Pipeline","title":"6. Open Discovery Phase Need","text":"","category":"section"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"Some future process algorithms may need type discovery after lifecycle init has run and after routes are known, but before normal scheduled stepping begins. This should not become public bootstrap API: the bootstrap/unsafe step remains loop-owned, and transient values created only to discover route shapes should be discarded after the run.","category":"page"},{"location":"internals/process_pipeline/","page":"Process Pipeline","title":"Process Pipeline","text":"The intended future direction is a small route-aware discovery phase exposed through the @ProcessAlgorithm API. That phase would let an algorithm declare or compute first-step value shapes without requiring its scheduled step! to run early. Until that exists, delayed algorithms that expose values to other steps must initialize those values in persistent state or be wrapped in a routine/composition whose first scheduled step makes the value available before consumers run.","category":"page"},{"location":"internals/routes_shares/#routes_shares_internals","page":"Routes and Shares","title":"Routes and Shares Internals","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route and Share are plan options. Resolution happens when a plan is wrapped and resolved as a concrete LoopAlgorithm.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Relevant files:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Definitions: src/RoutingInterface/RouteDef.jl, src/RoutingInterface/ShareDef.jl\nResolution backend: src/RoutingInterface/Resolving.jl, src/RoutingInterface/Backend.jl, src/RoutingInterface/Sharing.jl\nPlan integration: src/LoopAlgorithms/PlanOptions.jl, src/LoopAlgorithms/Preparation/Constructor.jl\nView integration: src/Context/View/StructDef.jl, src/Context/View/Locations.jl","category":"page"},{"location":"internals/routes_shares/#1.-Route-Resolution","page":"Routes and Shares","title":"1. Route Resolution","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route stores:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"source endpoint (from)\ntarget endpoint (to)\nrouted source variable names\nlocal aliases in target view\noptional transform function\noptional reverse transform function\nprecomputed match_by identities for from/to","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"resolve_options(reg, routes...) converts each route into:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"target subcontext name => tuple of resolved Route metadata, including source names, target aliases, transform, and reverse transform.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"to_sharedvar resolves endpoints by matcher identity in the registry, then binds concrete source/target keys.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Transform details:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(...; transform = f) or Route(...; reverse_transform = g) is restricted to exactly one mapping entry.\nThat single mapping can still be multi-source by mapping (:a, :b, ...) => :local_name.\nAt view-read time this becomes a VarLocation with tuple originalname and func = f, so the generated getter reads each source variable and calls f(a, b, ...).\nAt writeback time, transformed route aliases must have a reverse transform. Multi-source reverse transforms can return a tuple in source-variable order or a named tuple keyed by source variable name.","category":"page"},{"location":"internals/routes_shares/#2.-Share-Resolution","page":"Routes and Shares","title":"2. Share Resolution","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Share(a,b; directional=false) is converted to SharedContext metadata:","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"a -> b\nand also b -> a when non-directional.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"This metadata is attached to the target child's StepRouting.","category":"page"},{"location":"internals/routes_shares/#3.-How-Views-See-Them","page":"Routes and Shares","title":"3. How Views See Them","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"When creating SubContextView locations (src/Context/View/Locations.jl):","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"SharedContext contributes all variables from the shared subcontext.\nRoute metadata contributes only specified routed vars, plus transform and reverse transform if provided.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Both become VarLocation{:subcontext} entries, so reads and writes are directed to the source subcontext.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"That means returning a routed/shared variable from step! can update remote state, not only local state.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"The view constructor reconstructs resolved route/share tuples from their concrete tuple types. The runtime routing value selects the type-specialized view, but the view does not depend on const-propagating route/share values.","category":"page"},{"location":"internals/routes_shares/#4.-Errors-and-Validation","page":"Routes and Shares","title":"4. Errors and Validation","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If route/share endpoints are not present in the registry, resolution throws explicit errors listing available keys (see to_sharedvar and to_sharedcontext).","category":"page"},{"location":"internals/routes_shares/#5.-Relation-to-Packaging","page":"Routes and Shares","title":"5. Relation to Packaging","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"During Package(comp), routes are translated into VarAliases for internal subpackages (src/Packaging/Constructor.jl, src/Packaging/Utils.jl).","category":"page"},{"location":"internals/routes_shares/#6.-Plan-Local-Wiring","page":"Routes and Shares","title":"6. Plan-Local Wiring","text":"","category":"section"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Plain Route/Share options are stored on the plan node that contains them. DSL-local route/share statements become child-aligned local wiring, so the resolved StepRouting passed to a child is specific to that child location.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Nested plan routes remain local to the nested plan. A route/share assigned to a nested plan child itself is rejected because nested plan nodes do not have their own root context key; attach that route/share to a concrete child inside the nested plan instead.","category":"page"},{"location":"internals/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If both top-level and local routes expose the same target alias, local routes take precedence for that child step.","category":"page"},{"location":"user/threaded_process_managers/#threaded_process_managers_user","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use a ProcessManager when you already have a Process definition and want to run many independent jobs on Julia threads. The manager is not another way to write algorithms. It is a runtime layer that reuses initialized processes, loads one job into each process, runs those processes, and collects the results.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The main threaded entry point is:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runthreaded!(manager, jobs)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"You can also pass a thread schedule explicitly:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"run!(manager, jobs, Dynamic())\nrun!(manager, jobs, Static())\nrun!(manager, jobs, Greedy())","category":"page"},{"location":"user/threaded_process_managers/#Terms","page":"Threaded Process Managers","title":"Terms","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"A job is one item of work, such as one sample, one trajectory, or one simulation case.\nA managed process is a reusable Process that handles one job at a time.\nA slot is the manager record for one managed process. It stores the process, the current job, the latest result, and any error from that run.\nA recipe tells the manager how to load jobs, run processes, collect outputs, and reset state between jobs.\nmanager.state is manager-owned runtime data, commonly used for output buffers, counters, and shared parameters.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The API uses the word worker for a managed process because a manager can also wrap non-Process worker objects. For ordinary threaded Processes.jl usage, read worker as \"the reusable process in this slot\".","category":"page"},{"location":"user/threaded_process_managers/#What-manager.state-Is","page":"Threaded Process Managers","title":"What manager.state Is","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager.state is one shared object stored on the manager itself. Every recipe callback can read it, and callbacks that mutate it are mutating the same shared object.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"This is different from context(slot.worker):","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager.state is manager-wide state shared across all slots.\ncontext(slot.worker) is the current context of one specific worker process.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use manager.state for data that should survive across many jobs and should be visible to the manager as a whole. Common examples are:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"shared gradient buffers,\ncurrent global model parameters,\noptimizer state,\noutput arrays or logs,\ncounters such as number of processed samples,\nstatistics accumulated across workers.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use worker context for data that belongs to one worker run or one worker-local buffer. Examples are:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"the current job's input values,\ntemporary per-worker accumulation buffers,\none worker's random state,\none worker's local scratch arrays.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"In other words, if each worker should have its own copy, put it in the worker context. If all workers and manager callbacks should refer to the same long-lived object, put it in manager.state.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"You can create manager.state in two ways:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Pass state = your_state_object directly to ProcessManager(...).\nDefine initstate(config, manager) and let the manager build it from config.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"These are equivalent in the final manager object. The only difference is where the state object comes from.","category":"page"},{"location":"user/threaded_process_managers/#Why-manager.state-Is-Useful","page":"Threaded Process Managers","title":"Why manager.state Is Useful","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Without manager.state, shared training or batching logic has no single home. You would have to keep external mutable objects next to the manager and close over them manually in callbacks. That works, but it scatters the state outside the manager.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"With manager.state, the shared state is carried by the manager itself:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"prepare! can read shared parameters and load them into a worker,\nconsume! can append one worker's result into a shared output array,\nflush! can merge all worker-local buffers and apply one shared update,\nlater runs can continue from the updated shared state.","category":"page"},{"location":"user/threaded_process_managers/#Example:-Shared-Parameters","page":"Threaded Process Managers","title":"Example: Shared Parameters","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    initstate = config -> (;\n        params = Ref(config.initial_params),\n        nsamples = Ref(0),\n    ),\n\n    prepare! = (slot, job, manager) -> begin\n        ctx = context(slot.worker)[MyAlgo]\n        ctx.params[] = manager.state.params[]\n        ctx.x[] = job.x\n        manager.state.nsamples[] += 1\n        resetworker!(slot)\n    end,\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Here manager.state.params is the shared parameter value for the whole manager. Each worker gets a copy of that value loaded into its own context before a run. manager.state.nsamples counts all jobs seen by the manager, not just jobs seen by one worker.","category":"page"},{"location":"user/threaded_process_managers/#Example:-Shared-Output-Buffer","page":"Threaded Process Managers","title":"Example: Shared Output Buffer","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    initstate = config -> (; outputs = Float64[]),\n\n    consume! = (slot, job, manager) -> begin\n        ctx = context(slot.worker)[MyAlgo]\n        push!(manager.state.outputs, ctx.value[])\n    end,\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Here the output array belongs to the manager, not to any one worker. Each finished worker appends one value into the shared output buffer.","category":"page"},{"location":"user/threaded_process_managers/#Whole-Manager-Workflow","page":"Threaded Process Managers","title":"Whole Manager Workflow","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"A threaded manager run has four parts:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Construction creates the fixed slots. If you pass workers = ..., those process objects are wrapped as-is. If you omit workers, the recipe must define makeworker; the manager builds the processes for you. For Process workers, makecontext can build separate per-slot contexts while keeping the same algorithm.\nDispatch assigns one job to one available slot. The manager stores the job in slot.job, clears the previous slot.result and slot.error, runs prepare!, calls runarguments, then starts the process. Use prepare! for persistent context changes. Use runarguments for runtime @input values by returning a named tuple. For Process workers, lifetime, repeats, and repeat in that tuple control the launch lifetime; the remaining keys are passed as runtime inputs.\nCompletion happens inside the threaded job iteration. When a process finishes, the manager runs finalize!, afterrun!, consume!, and release!, then makes the slot available for another job.\nFlushing is manager-level synchronization. flush_policy decides when flush! runs. Use flush! to merge slot-local buffers into manager.state, external storage, or another object.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"In threaded mode, default Process workers run inline inside a Threads.@threads iteration. This avoids one task spawn per job. Recipe callbacks still run as part of the slot lifecycle, so consume! and flush! remain the right places to move finished values out of process contexts.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The recipe is stored directly in ProcessManager{Recipe,...}. A named tuple of closures therefore keeps the concrete closure types visible to Julia. For lower overhead, also pass job_type, result_type, scratch_type, or error_type when those slot field types are known.","category":"page"},{"location":"user/threaded_process_managers/#Worker-Ownership","page":"Threaded Process Managers","title":"Worker Ownership","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The usual form is to let the manager create and own its processes:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n\n    prepare! = (slot, job, manager) -> begin\n        ctx = context(slot.worker)[MyAlgo]\n        ctx.value[] = job.value\n        resetworker!(slot)\n    end,\n)\n\nmanager = ProcessManager(recipe; nworkers = 4)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"In this form, makeworker is called when the manager is created. The manager stores those processes and their contexts in slots(manager). Later calls to runthreaded!(manager, jobs) do not create new processes or new contexts unless your recipe does so.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For Process workers, the manager can also build the algorithm once and let the recipe build each process context separately:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    makeworker = (idx, manager) -> Process(MyAlgo; repeats = 1),\n\n    makecontext = (idx, manager, template) -> begin\n        initialized = init(\n            getalgo(template),\n            Init(MyAlgo; seed = idx),\n        )\n        context(initialized)\n    end,\n)\n\nmanager = ProcessManager(recipe; nworkers = 4)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Here makeworker is still called once. makecontext is called once per slot, including slot 1. The manager installs each returned context on a process that uses the template task description. Use this when all processes should run the same algorithm, but each process needs separate buffers, random state, or initial values.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"You can inspect manager-owned processes with:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"slots(manager)\nworkers(manager)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Closing an owning manager also closes its processes:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"close(manager)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"You can also pass processes that were built elsewhere:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(recipe; workers = existing_workers)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"This wraps the existing processes in new slots. It does not create contexts. Use this form when some other object owns the processes or when the processes must be constructed before the manager exists.","category":"page"},{"location":"user/threaded_process_managers/#On-Demand-Workers","page":"Threaded Process Managers","title":"On-Demand Workers","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use OnDemandWorkers when the job should define the worker that runs it. This is a different manager operation mode from reusable workers: slots are created upfront, but workers are not. Each dispatched job calls makeworker(idx, manager, job) and installs the returned worker into the slot.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"This is useful for automating long lived experiments where the job record is the experiment specification. For example, one job can carry the algorithm type, initialization options, seed, output location, and a worker-specific finalizer. The manager still gives you bounded threaded scheduling, error accounting, flushing, and a consistent result collection lifecycle, but each experiment can choose its own worker shape.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Slots also keep a slot.name::Symbol. By default names are :worker_1, :worker_2, and so on. Define workername(idx, manager, job) when a job should provide a stable experiment label, so later result lookup and logs can refer to the same name.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    initstate = config -> (; results = []),\n    workername = (idx, manager, job) -> job.name,\n    makeworker = (idx, manager, job) -> Process(\n        job.algo,\n        Init(job.algo; seed = job.seed);\n        repeats = 1,\n    ),\n    workerfinalizer = (slot, job, manager) -> job.finalizer,\n    consume! = (slot, job, manager) -> push!(\n        manager.state.results,\n        (; name = slot.name, output = job.readout(slot.worker)),\n    ),\n)\n\nmanager = ProcessManager(\n    recipe;\n    nworkers = 4,\n    worker_lifecycle = OnDemandWorkers(destroy_after_finalize = false),\n    worker_type = Process,\n)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Pass worker_type when different jobs may return different concrete worker types. For Process workers, Process(job.algo; ...) usually has a concrete type that depends on job.algo, so use worker_type = Process when jobs may select different concrete Process{LoopAlgo} specializations. If every job returns exactly the same worker type, pass that concrete type as worker_type to keep the slot field concrete. If you omit worker_type, on-demand slots use Any for maximum flexibility.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Worker names are Symbol by default. If you need another name type, pass name_type, but symbols are preferred because they are compact and easy to use as result keys.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"workerfinalizer may select a finalizer function from the job. That function is called as finalizer(worker, slot, job, manager), or with fewer trailing arguments if it accepts less. Return nothing to use the default finalizer for that job.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"By default OnDemandWorkers() destroys the job worker after consume! and release!, using destroyworker! when the recipe defines it, then close!, and otherwise the default worker close behavior. Pass destroy_after_finalize = false to keep the finished worker in the slot until the next job replaces it.","category":"page"},{"location":"user/threaded_process_managers/#Threaded-Scheduling","page":"Threaded Process Managers","title":"Threaded Scheduling","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runthreaded!(manager, jobs) uses Dynamic() scheduling by default.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runthreaded!(manager, jobs)\nrunthreaded!(manager, jobs, Static())\nrunthreaded!(manager, jobs, Greedy())","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The schedule controls how Julia assigns job iterations to threads and how the manager maps those iterations onto slots:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Schedule Slot mapping Use when Main cost\nDynamic() Each iteration borrows a slot from a bounded channel. Job runtimes may vary, or you want the default bounded scheduling behavior. Channel traffic for every job.\nStatic() Each Julia thread uses slots(manager)[Threads.threadid()]. Jobs have similar cost and you want a stable thread-to-slot mapping. Requires at least Threads.maxthreadid() slots and can leave work imbalanced.\nGreedy() Greedy Julia scheduling with the same bounded slot pool as Dynamic(). Job costs are uneven enough that greedy scheduling improves balance. Can lose on tiny jobs because scheduling overhead dominates.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Dynamic() is the safest default for heterogeneous job streams. Static() is often fastest for many equal CPU-bound jobs because it avoids the slot-pool channel and each thread reuses the same slot. Greedy() is worth measuring for long-tailed job costs, for example when a few simulations or samples take much longer than the rest.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For local comparisons, run the threaded mode profiler from the repository root:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia --project=. --threads=auto Profiling/manager/threaded_modes/compare_threaded_modes.jl\njulia --project=. --threads=auto Profiling/manager/threaded_modes/actual_process_workloads.jl","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The convenience form below is equivalent to runthreaded!:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"run!(manager, jobs, Dynamic())","category":"page"},{"location":"user/threaded_process_managers/#Run-Lifecycle","page":"Threaded Process Managers","title":"Run Lifecycle","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For each job, the manager uses this order:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Borrow a free slot.\nStore the job in slot.job.\nCall prepare!(slot, job, manager).\nCall runarguments(slot, job, manager).\nStart the process with the named tuple returned by runarguments. For Process workers, lifetime, repeats, and repeat are reserved launch controls; all other keys are passed as runtime @input values.\nWait for the process to finish. In threaded mode this means the inline process run has returned. In the polling mode this means isdone reported that the process is finished.\nCall finalize!(slot, job, manager), or wait(slot.worker); close(slot.worker) if no finalize! callback exists. This is the first hook after the process has finished and the last hook before result-reading callbacks run.\nCall afterrun!(slot, job, manager).\nCall consume!(slot, job, manager).\nCall release!(slot, job, manager).\nReturn the slot to the pool.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"If a recipe defines start!(slot, job, manager), that callback replaces steps 4 and 5. Use start! only when you want to take over process launch completely.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"For Process workers, threaded mode runs the process inline inside the current threaded iteration through runprocessinline!. The non-threaded manager run uses:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"run(slot.worker)\nwait(slot.worker)\nclose(slot.worker)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"close(worker) stores the finished process context back on the worker when the process returns a context. That makes consume! the right place to read final context values.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"If a job needs to affect both persistent context and loop-level runtime inputs, use two different steps: prepare the context in prepare!, then pass runtime inputs from runarguments.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"<<<<<<< HEAD","category":"page"},{"location":"user/threaded_process_managers/#What-flush!-Is-For","page":"Threaded Process Managers","title":"What flush! Is For","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"flush! is a manager-level callback that runs after completed worker runs are available. Its job is to take data that has already been produced by workers and merge it into one shared destination.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The key point is that flush! is not the place where one worker finishes. That happens earlier, through finalize!, afterrun!, consume!, and release!. flush! runs later, according to flush_policy, after one or more completed runs are waiting to be flushed.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"In practice, flush! is useful when workers accumulate local data that should only be merged occasionally. Common examples are:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"combine per-worker gradients into one global gradient update,\ngather worker-local output batches into one manager-owned buffer,\nwrite many finished results to disk in one batch,\nclear worker-local accumulation buffers after their contents were merged.","category":"page"},{"location":"user/threaded_process_managers/#Exact-Timing","page":"Threaded Process Managers","title":"Exact Timing","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"The manager only calls flush! when at least one run has completed since the previous flush.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"FlushAtEnd(): flush! runs once after the whole run!(manager, jobs) or runthreaded!(manager, jobs) call has finished.\nFlushEvery(n; drain = true): flush! runs after every n completed runs. With drain = true, active slots are finalized before the flush. With drain = false, only already-finished slots contribute.\nNoFlush(): flush! is never called automatically.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"So flush! is a batching point, not a per-job callback.","category":"page"},{"location":"user/threaded_process_managers/#flush!-Versus-consume!","page":"Threaded Process Managers","title":"flush! Versus consume!","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use consume! when you want to react to one finished worker immediately.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use flush! when you want to merge or apply results from many finished workers together.","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"That distinction matters in learning-style workloads:","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"consume!: append one worker's scalar loss to a history array.\nflush!: sum gradients from all workers, apply one optimizer step, then zero worker-local gradient buffers.","category":"page"},{"location":"user/threaded_process_managers/#Example:-Batch-Gradient-Update","page":"Threaded Process Managers","title":"Example: Batch Gradient Update","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;\n    initstate = config -> (;\n        params = Ref(config.initial_params),\n        lr = config.lr,\n    ),\n\n    flush! = manager -> begin\n        total_grad = 0.0\n\n        for slot in slots(manager)\n            ctx = context(slot.worker)[MyAlgo]\n            total_grad += ctx.grad[]\n            ctx.grad[] = 0.0\n        end\n\n        manager.state.params[] -= manager.state.lr * total_grad\n=======\n## Running Custom Code On Worker Threads\n\nUse threaded manager mode when setup work must run on the same Julia thread as\nthe process loop:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia runthreaded!(manager, jobs)","category":"page"},{"location":"user/threaded_process_managers/#Equivalent-convenience-forms:","page":"Threaded Process Managers","title":"Equivalent convenience forms:","text":"","category":"section"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"run!(manager, jobs, Dynamic()) run!(manager, jobs, Static()) run!(manager, jobs, Greedy())","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nIn these modes, each job owns one slot for the duration of a threaded iteration.\nFor a `Process` worker and no custom `start!`, the code executed on that thread\nis:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia prepare!(manager.recipe, slot, job, manager) kwargs = runarguments(manager.recipe, slot, job, manager) runprocessinline!(slot.worker; kwargs...) finalize!(manager.recipe, slot, job, manager) afterrun!(manager.recipe, slot, job, manager) consume!(manager.recipe, slot, job, manager) release!(manager.recipe, slot, job, manager)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nThat makes `prepare!` the normal place for per-job thread-local setup before the\nloop algorithm runs:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia recipe = (;     makeworker = (idx, manager) -> Process(MyAlgorithm; repeats = 1),     prepare! = (slot, job, manager) -> begin         # This runs on the same thread that will run the process loop when using         # runthreaded! or run!(manager, jobs, Dynamic()/Static()/Greedy()).         ctx = context(slot.worker)[MyAlgorithm]         ctx.input[] = job.input         ctx.thread_id[] = Threads.threadid()         return nothing     end,     runarguments = (slot, job, manager) -> (; temperature = job.temperature),     consume! = (slot, job, manager) -> push!(manager.state.outputs, job.id), )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nUse `runarguments` when the pre-run code should compute loop-level runtime\ninputs immediately before launch. For `Process` workers, return `lifetime`,\n`repeats`, or `repeat` from the same named tuple to control the per-job process\nlifetime:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia recipe = (;     makeworker = (idx, manager) -> Process(MyAlgorithm; repeats = 1),     prepare! = (slot, job, manager) -> begin         context(slot.worker)[MyAlgorithm].input[] = job.input         return nothing     end,     runarguments = (slot, job, manager) -> begin         # Also runs on the worker thread in threaded manager mode.         (;             temperature = job.temperature,             thread_id = Threads.threadid(),             repeats = job.repeats,         )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"d6b3a8504846923aa37cef15958a4fded63b4258","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"end,","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":")","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\n<<<<<<< HEAD\nEach worker accumulates its own `ctx.grad[]` locally. `flush!` reads those local\nbuffers, combines them, updates the shared manager parameters once, and clears\nthe local buffers.\n\n### Why `flush!` Exists\n\nWithout `flush!`, every worker completion would have to update shared state\nimmediately. That often forces extra synchronization or makes the logic harder\nto reason about.\n\n`flush!` gives you one explicit place to say: \"all completed worker results up\nto this point may now be merged into shared manager state.\"\n=======\nUse `lifetime` when the job already has a `Lifetime` object, for example\n`Repeat(10)`, `Until(...)`, or `AtLeastAtMost(...)`:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia runarguments = (slot, job, manager) -> (;     temperature = job.temperature,     lifetime = job.lifetime, )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nDo not return both `lifetime` and `repeats` for one job. These keys are consumed\nby the manager launch path and are not passed to runtime `@input` validation for\n`Process` workers.\n\nUse `start!` only when the launch itself must be custom. Defining `start!`\nreplaces the default `runarguments` + `runprocessinline!` launch, so call\n`runprocessinline!` yourself if you still want inline `Process` execution:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia recipe = (;     makeworker = (idx, manager) -> Process(MyAlgorithm; repeats = 1),     prepare! = (slot, job, manager) -> begin         context(slot.worker)[MyAlgorithm].input[] = job.input         return nothing     end,     start! = (slot, job, manager) -> begin         # Custom thread-local setup immediately before the loop starts.         job.before_run!(Threads.threadid())         return runprocessinline!(             slot.worker;             temperature = job.temperature,         )     end,     isdone = (slot, manager) -> true,     finalize! = (slot, job, manager) -> nothing, )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nIn the polling manager path, `prepare!` and `runarguments` run on the manager\ntask, and `run(slot.worker; kwargs...)` starts the process asynchronously. Use\nthreaded manager mode when same-thread setup is part of the contract.\n>>>>>>> d6b3a8504846923aa37cef15958a4fded63b4258\n\n## What `finalize!` Is For\n\n`finalize!` is for making a just-finished process ready to be inspected. It is\ncalled after the process run has completed, before `afterrun!`, `consume!`, and\n`release!`.\n\nFor normal `Process` workers, the default finalization is:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia wait(slot.worker) close(slot.worker)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nThat default is important because `close` stores the returned context back on\nthe process. After that, `consume!` can read `context(slot.worker)` and see the\nfinished values.\n\nDefine `finalize!` yourself when the default wait-and-close behavior is not the\nright finish step. Common cases are:\n\n- a custom worker type needs a different method to retrieve the final result,\n- the worker returns a value that should be placed in `slot.result`,\n- close should be delayed because the worker is owned by another object,\n- extra validation must run before `consume!` reads the finished context.\n\nDo not use `finalize!` for normal result accumulation. Put that in `consume!`,\nwhich runs immediately after finalization.\n\n## Chunked Inline Workers\n\nUse `InlineChunkWorker` when each slot should keep an `InlineProcess` on one\ntask for several examples. `runchunks!` groups examples into vector chunks, and\neach chunk is dispatched as one manager job. Inside that chunk task, the recipe\nloads one example at a time into the inline process context and runs the inline\nprocess synchronously.\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia worker = InlineChunkWorker(InlineProcess(MyAlgo; repeats = 1))","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;     resetexample! = (process, example, slot, manager) -> begin         ctx = context(process)[MyAlgo]         empty!(ctx.buffer)     end,","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"loadexample! = (process, example, slot, manager) -> begin\n    ctx = context(process)[MyAlgo]\n    ctx.x[] = example.x\nend,\n\nafterexample! = (process, example, result, slot, manager) -> begin\n    ctx = context(process)[MyAlgo]\n    push!(manager.state.outputs, ctx.y[])\nend,","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":")","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(     recipe;     workers = (worker,),     job_type = Vector{eltype(dataset)}, )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runchunks!(manager, dataset; chunksize = 128)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nThe default `runchunks!` form uses the polling manager path and starts one task\nper chunk. To run chunks through the threaded manager schedules instead, pass a\nschedule:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia runchunks!(manager, dataset, Dynamic(); chunksize = 128) runchunks!(manager, dataset, Static(); chunksize = 128) runchunks!(manager, dataset, Greedy(); chunksize = 128)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nIn scheduled chunk mode, `beforechunk!`, `resetexample!`, `loadexample!`,\n`afterexample!`, and `afterchunk!` run on the threaded iteration that owns the\nslot, and no extra task is spawned for the chunk.\n\n`resetexample!` is optional. If it is omitted, context state carries from one\nexample to the next inside a chunk. `loadexample!` is required. `beforechunk!`\nand `afterchunk!` are optional hooks around the whole chunk.\n\n## Recipe Callbacks\n\nA recipe can be a named tuple or an object with methods for these callbacks.\nCallbacks can accept fewer trailing arguments if they do not need all of them.\nThe recipe object is stored as a concrete field of the manager, so anonymous\nfunctions in a named tuple are part of the manager type.\n\n- `initstate(config, manager)`: build `manager.state` from user configuration.\n- `makeworker(idx, manager)`: create process `idx` when `workers` is not passed.\n- `makeworker(idx, manager, job)`: create the worker for one job when\n  `worker_lifecycle = OnDemandWorkers()`.\n- `workername(idx, manager)`: name reusable workers at manager construction.\n- `workername(idx, manager, job)`: name an on-demand worker from job data.\n- `makecontext(idx, manager, template)`: for manager-owned `Process` workers,\n  build the context for slot `idx` from the template process.\n- `prepare!(slot, job, manager)`: write one job into a process before it starts.\n  This is the usual place to mutate context, call `reinitworker!`, or call\n  `partialinitworker!`. In threaded manager mode, this callback runs on the same\n  thread that will run the process loop.\n- `runarguments(slot, job, manager)`: return a named tuple of runtime keyword\n  arguments for the implicit `run(...)` call. This callback may also run\n  arbitrary manager-side code before launch. For example,\n  `(; temperature = job.temperature)` becomes\n  `run(slot.worker; temperature = job.temperature)`. In threaded manager mode,\n  this callback runs on the same thread that will run the process loop. For\n  `Process` workers, `lifetime`, `repeats`, and `repeat` are reserved launch\n  controls and are removed before runtime `@input` validation.\n- `start!(slot, job, manager)`: advanced custom process start. If this callback\n  exists, it replaces `runarguments` and the implicit `run(...)` call. For\n  `Process` workers in threaded manager mode, call `runprocessinline!` inside\n  `start!` when custom launch code should still run the process inline.\n- `isdone(slot, manager)`: custom completion check. Defaults to\n  `isdone(worker)` for `Process` workers.\n- `finalize!(slot, job, manager)`: custom finish step called after the process\n  has completed and before `afterrun!` and `consume!`. Defaults to\n  `wait(worker); close(worker)` for `Process` workers.\n- `workerfinalizer(slot, job, manager)`: select a finalizer function for the\n  current job. Ignored when `finalize!` is present.\n- `afterrun!(slot, job, manager)`: optional hook after finalization.\n- `consume!(slot, job, manager)`: read a finished process and accumulate output.\n- `release!(slot, job, manager)`: clear local state after `consume!`.\n- `flush!(manager)`: move slot-local buffers into manager state or another\n  destination.\n- `close!(slot, manager)`: custom process close.\n- `destroyworker!(slot, job, manager)`: cleanup hook for\n  `OnDemandWorkers(destroy_after_finalize = true)`. If this is missing, the\n  manager falls back to `close!`.\n- `onerror!(slot, err, manager)`: custom error handling.\n- `beforechunk!(process, chunk, slot, manager)`: optional chunk setup for\n  `InlineChunkWorker`.\n- `resetexample!(process, example, slot, manager)`: optional per-example reset\n  for `InlineChunkWorker`.\n- `loadexample!(process, example, slot, manager)`: required per-example context\n  load for `InlineChunkWorker`.\n- `afterexample!(process, example, result, slot, manager)`: optional\n  per-example consume hook for `InlineChunkWorker`.\n- `afterchunk!(process, chunk, slot, manager)`: optional chunk cleanup for\n  `InlineChunkWorker`.\n\n`config` is construction input. `state` is runtime data owned by the manager.\nPrefer putting shared runtime buffers, counters, parameters, optimizer state,\nand logs in `initstate` instead of keeping them as unrelated external mutable\nobjects.\n\n## Context Reuse\n\nThe manager reuses the same process objects. Context reuse depends on what your\nrecipe does in `prepare!`.\n\nUse direct mutation when only a few fields change. After mutating the context,\ncall `resetworker!(slot)` if the next run should restart the process counters\nfrom the beginning:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia prepare! = (slot, job, manager) -> begin     ctx = context(slot.worker)[MyAlgo]     ctx.x[] = job.x     empty!(ctx.buffer)     resetworker!(slot) end","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\n`resetworker!` does not reset context values. For a `Process`, it sets\n`loopidx = 1`, `tickidx = 1`, `paused = false`, `shouldrun = true`,\n`starttime = nothing`, and `endtime = nothing`, then calls\n`reset!(getalgo(slot.worker))`. It does not replace `runtime_context`,\n`task`, or `lastresult`. Arrays, refs, and other values already stored in\n`context(slot.worker)` remain unchanged. In the example above, `ctx.x[]` keeps\nthe value assigned from `job.x`, and `ctx.buffer` is cleared only because the\nrecipe calls `empty!`.\n\nUse `reinitworker!` when the job should replace the whole process context\nthrough the normal init path:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia prepare! = (slot, job, manager) -> reinitworker!(     slot,     Init(MyAlgo; x = job.x), )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\n`reinitworker!` runs `init(getalgo(slot.worker), ...)` and installs the new\ncontext on the process. Use it when previous context contents should not carry\ninto the next job.\n\nUse `partialinitworker!` when only one algorithm or state target should be\nrebuilt through its `init` method:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia prepare! = (slot, job, manager) -> partialinitworker!(     slot,     Init(MyAlgo; x = job.x), )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\n`partialinitworker!` starts from the current context and replaces only the\ntargeted subcontext values. Other subcontexts keep their current values.\n\nUse `runarguments` for loop-level runtime `@input` values:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia runarguments = (slot, job, manager) -> (; temperature = job.temperature)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nYou can use both for the same job. The manager calls `prepare!` first, then\n`runarguments`, then `run(slot.worker; temperature = job.temperature)`.\n\nDirect mutation is usually faster. `reinitworker!` and `partialinitworker!` are\nuseful when the context shape, inputs, or initialized state must be rebuilt. Do\nnot create a new `Process` inside a callback unless you intentionally want to\ngive up context reuse.\n\n## Result Collection\n\nUse `consume!` to read one finished process. This hook runs after the process\nhas finished and been finalized.\n\nIf processes are reused, avoid storing mutable context objects for later unless\nyou know they will not be overwritten. Store copied values instead:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia consume! = (slot, job, manager) -> begin     ctx = context(slot.worker)[MyAlgo]     push!(manager.state.outputs, (; value = ctx.value[], loss = ctx.loss[])) end","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\n## Flush Policies\n\n`flush_policy` controls when `flush!(manager)` is called.\n\n- `FlushAtEnd()` is the default. It runs all jobs first, drains all active\n  slots, then calls `flush!` once.\n- `NoFlush()` never calls `flush!` automatically. Use this when `consume!`\n  handles all result collection.\n- `FlushEvery(n; drain = true)` calls `flush!` after every `n` completed\n  process runs. When `drain = true`, all active slots are finalized before\n  flushing. When `drain = false`, only already-finished slots are flushed.\n\n`flush!` runs after finished values are available, so it can merge slot-local\nbuffers without making those buffers thread-safe.\n\n## Manual Non-Threaded Scheduling\n\nThe manager also has a lower-level, polling-based interface:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia dispatch!(manager, job) poll!(manager) wait(manager) drain!(manager)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nUse this only when you need manual control over dispatch and polling. For normal\nthreaded `Process` runs, prefer `runthreaded!`.\n\n`wait(manager)` waits until all currently active workers finish. `drain!(manager)`\nalso applies the final flush policy after all active workers have finished.\n\n`poll_interval = 0.0` means the manager yields while waiting. A positive\n`poll_interval` sleeps for that many seconds between checks when all slots are\nbusy.\n\n## Type Hints\n\nFor lower overhead, pass concrete slot field types when they are known:\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia template_worker = Process(MyAlgo; repeats = 1)","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(     recipe;     nworkers = 4,     jobtype = eltype(jobs),     resulttype = typeof(template_worker), )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nUsually `job_type = eltype(jobs)` is the most important one. If a callback\nstores a result in `slot.result`, set `result_type` to that result type.\n\nThe manager stores its slots in a tuple. This keeps the slot container type\nfixed after construction and leaves room for processes with different concrete\ntypes. `workers(manager)` returns the same fixed-shape tuple of process objects.\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"@docs Processes.ProcessManager Processes.WorkerSlot Processes.FlushPolicy Processes.FlushAtEnd Processes.NoFlush Processes.FlushEvery Processes.WorkerLifecycle Processes.ReuseWorker Processes.OnDemandWorkers Processes.ThreadsType Processes.Static Processes.Dynamic Processes.Greedy Processes.slots Processes.workers Processes.copyworker Processes.InlineChunkWorker Processes.runchunks! Processes.prepare! Processes.runarguments Processes.start! Processes.beforechunk! Processes.resetexample! Processes.loadexample! Processes.afterexample! Processes.afterchunk! Processes.dispatch! Processes.poll! Processes.drain! Processes.run! Processes.runthreaded! Processes.resetworker! Processes.reinitworker! Processes.partialinitworker!","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\n## Manager-Owned Process Example\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia template = Process(     MyAlgo,     Init(MyAlgo; value = Ref(0), local_buffer = Int[]),     Override(MyAlgo; delta = 3);     repeats = 20, )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;     initstate = config -> (;         output = Int[],         scale = config.scale,     ),","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"makeworker = (idx, manager) -> copyprocess(template; context = deepcopy(context(template))),\n\nprepare! = (slot, job, manager) -> begin\n    ctx = context(slot.worker)[MyAlgo]\n    ctx.value[] = job.value * manager.state.scale\n    resetworker!(slot)\nend,\n\nflush! = manager -> begin\n    for slot in slots(manager)\n        ctx = context(slot.worker)[MyAlgo]\n        append!(manager.state.output, ctx.local_buffer)\n        empty!(ctx.local_buffer)\n    end\nend,","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":")","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(     recipe;     nworkers = 4,     config = (; scale = 2),     flushpolicy = FlushAtEnd(),     jobtype = eltype(jobs),     result_type = typeof(template), )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runthreaded!(manager, jobs) manager.state.output","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"\nThe manager calls `flush!` automatically according to `flush_policy`; normal\ncode does not call it directly.\n\n## Existing Process Example\n","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"julia workers = [Process(MyAlgo; repeats = 1) for _ in 1:4]","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"recipe = (;     prepare! = (slot, job, manager) -> begin         ctx = context(slot.worker)[MyAlgo]         ctx.value[] = job.value         resetworker!(slot)     end,","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"consume! = (slot, job, manager) -> begin\n    ctx = context(slot.worker)[MyAlgo]\n    push!(manager.state.outputs, ctx.value[])\nend,\n\ninitstate = config -> (; outputs = Int[]),","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":")","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"manager = ProcessManager(     recipe;     workers,     config = (;),     flushpolicy = NoFlush(),     jobtype = eltype(jobs),     result_type = eltype(workers), )","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"runthreaded!(manager, jobs) manager.state.outputs ```","category":"page"},{"location":"user/threaded_process_managers/","page":"Threaded Process Managers","title":"Threaded Process Managers","text":"Use existing processes only when they must be owned or prepared outside the manager. Otherwise prefer the manager-owned form with makeworker.","category":"page"},{"location":"man/usage/#usage","page":"Usage Guide","title":"Usage Guide","text":"","category":"section"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"This page is kept only as a compatibility entry point for older links.","category":"page"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"For current documentation, use the split docs below.","category":"page"},{"location":"man/usage/#User-Documentation","page":"Usage Guide","title":"User Documentation","text":"","category":"section"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"Algorithms and States\nReferencing Algorithms\nContexts and Indexing\nRoutes and Shares\nInit, Overrides, and Runtime Inputs\nVars (Var Selectors)\nLifetime\nRunning, Wait, Fetch\nCopying Processes\nThreaded Process Managers\nValue Semantics and Unique","category":"page"},{"location":"man/usage/#Internals","page":"Usage Guide","title":"Internals","text":"","category":"section"},{"location":"man/usage/","page":"Usage Guide","title":"Usage Guide","text":"Registry Internals\nContext Internals\nRoutes and Shares Internals\nProcess Pipeline Internals","category":"page"},{"location":"internals/contexts/#context_internals","page":"Contexts","title":"Context Internals","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"The runtime data stack is:","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"ProcessContext\nSubContext\nSubContextView","category":"page"},{"location":"internals/contexts/#1.-ProcessContext","page":"Contexts","title":"1. ProcessContext","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"ProcessContext{D,Reg} holds (src/Context/StructDefs.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"subcontexts::D: named tuple of subcontexts plus globals.\nregistry::Reg: a NameSpaceRegistry used for static routing and lookup.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Access patterns (src/Context/ProcessContexts.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"pc[:name] or pc.name by subcontext symbol.\npc[obj] by algorithm/state value/type (resolved through registry key).","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"globals is a regular field in subcontexts; runtime code injects process-level values there (like process, lifetime, algo).","category":"page"},{"location":"internals/contexts/#2.-SubContext","page":"Contexts","title":"2. SubContext","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"SubContext{Name,Data} stores (src/Context/StructDefs.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"data::NamedTuple: local variables owned by that entity.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Initialization builds empty SubContexts for every registry key, then fills them by init.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Route/share metadata is deliberately not stored on SubContext. Plan routing is resolved into step-local StepRouting values and attached to SubContextView types while a child runs. This keeps persistent context shape independent from execution-plan wiring.","category":"page"},{"location":"internals/contexts/#3.-SubContextView","page":"Contexts","title":"3. SubContextView","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"step!, init, and cleanup run against a SubContextView (src/Context/View/StructDef.jl).","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"A view carries:","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"the full context,\nthe current identifiable instance,\noptionally injected locals.\nroute/share metadata for the current step, as type parameters.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Property access is generated through VarLocations (src/Context/View/Locations.jl):","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"local vars,\nshared-context vars from the current step routing,\nrouted vars from the current step routing,\ninjected vars.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Name precedence for reads is determined by NamedTuple merge order. Later groups override earlier groups:","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"injected vars\nlocal vars\nrouted vars\nshared vars","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"This means local and injected names override route/share names on collisions.","category":"page"},{"location":"internals/contexts/#4.-Merging-and-Replacing","page":"Contexts","title":"4. Merging and Replacing","text":"","category":"section"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"merge(view, namedtuple) (src/GeneratedCode/SubContextView.jl) maps return names back to concrete target subcontexts and variables.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"Existing mapped variable: update that mapped target.\nUnknown variable: added to the current local subcontext.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"replace(view, (;SubKey => nt)) replaces the full subcontext and is used during init.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"merge_into_subcontexts (src/Context/ProcessContexts.jl) enforces that subcontext structure remains valid.","category":"page"},{"location":"internals/contexts/","page":"Contexts","title":"Contexts","text":"A type-change guard in generated merge asserts the new ProcessContext type stays identical, preventing accidental type instability.","category":"page"},{"location":"user/algorithms_states/#algorithms_states_user","page":"Algorithms and States","title":"Algorithms and States","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"ProcessAlgorithm and ProcessState are the two main building blocks you compose into a process.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Use ProcessAlgorithm for something that actively participates in the loop by implementing Processes.step!.\nUse ProcessState for data that should be initialized into a subcontext and then shared or read by algorithms.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Both are process entities: values that the package knows how to place inside a process. When a process is prepared, each entity gets a named part of the process context. That named part is its subcontext.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"User methods receive a view of the current subcontext, plus any routed or shared values that were made visible to it. In normal code, treat that view like a read-only input object. Return a NamedTuple to write values back.","category":"page"},{"location":"user/algorithms_states/#Lifecycle-Hooks","page":"Algorithms and States","title":"Lifecycle Hooks","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"The framework lifecycle is:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"init phase\nlooped step! phase\ncleanup phase","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Order matters here: states are initialized first, then algorithms. Cleanup follows the same order. This means an algorithm can read values prepared by an earlier state if those values are routed or shared to it.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Two details from the implementation are worth knowing:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"cleanup runs on natural finite completion.\nIf a process is interrupted, paused, or runs under Indefinite(), the current context is stored without automatic cleanup.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"There is no built-in prepare! hook in the current pipeline. If you want a one-time preparation step, fold it into init or guard the first step! with a flag in state.","category":"page"},{"location":"user/algorithms_states/#Full-Definitions","page":"Algorithms and States","title":"Full Definitions","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"struct MyAlgo <: ProcessAlgorithm\n    gain::Float64\nend\n\nfunction Processes.init(a::MyAlgo, context)\n    x = 0.0\n    return (; x)\nend\n\nfunction Processes.step!(a::MyAlgo, context)\n    (; x) = context\n    x = x + a.gain\n    return (; x)\nend\n\nfunction Processes.cleanup(::MyAlgo, context)\n    return (;)\nend","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"struct MyState <: ProcessState end\n\nfunction Processes.init(::MyState, context)\n    return (; shared_buffer = Float64[])\nend","category":"page"},{"location":"user/algorithms_states/#Macro-Shortcuts","page":"Algorithms and States","title":"Macro Shortcuts","text":"","category":"section"},{"location":"user/algorithms_states/#@ProcessAlgorithm","page":"Algorithms and States","title":"@ProcessAlgorithm","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm creates the struct and the needed step! methods from a function signature.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm function Accumulate(x, gain)\n    x = x + gain\n    return (; x)\nend","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"You can still define init and cleanup manually for the generated type.","category":"page"},{"location":"user/algorithms_states/#Macro-Generated-Algorithm-Semantics","page":"Algorithms and States","title":"Macro-Generated Algorithm Semantics","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm also supports managed local state and configuration fields. Managed local state is data that belongs to one algorithm and is created during init, then read again during each step!.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"The signature is split into:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"plain positional arguments: values read from context during Processes.step!\n@managed(...) positional arguments: algorithm-owned values created during Processes.init\nnormal keyword arguments: values read from context during Processes.step!, using the declared default when absent\noptional trailing @input((; ...)) / @inputs((; ...)) / @init((; ...)): values read only while constructing managed state\noptional @config ... declarations before the function: fields stored on the generated algorithm object","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Example:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessAlgorithm begin\n    @config n::Int = 8\n    @config damp = 1.0\n\n    function MyAlgo(\n        signal,\n        @managed(buffer = zeros(n)),\n        @managed(scale),\n        @managed(metric = 0.0);\n        @inputs((; scale = 2.0))\n    )\n        @inbounds for i in eachindex(signal)\n            buffer[i] = damp * scale * signal[i]\n        end\n        metric = sum(buffer)\n        return (; buffer, scale, metric)\n    end\nend","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Rules worth knowing:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@managed(name) captures name from the init context into local managed state.\n@managed(name = expr) evaluates expr during Processes.init.\n@managed(a, b = expr, c = expr2) expands to multiple managed locals in order.\n@input/@inputs/@init may only appear once and must be the last keyword-like item.\n@config fields must have defaults and become fields on the generated struct. You can write them in a surrounding block or as a prelude like @ProcessAlgorithm @config seed = 1 function MyAlgo(...) ... end.\ninside the algorithm body, config fields are available directly by name. Use seed, not config.seed.\nplain positional arguments are runtime-only and are not available while constructing managed state.\nJulia where signatures are supported.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"For a macro-generated algorithm MyAlgo, the main entrypoints are:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"direct/bootstrap call: step!(MyAlgo(), args...; @inputs((; ...)))\ninit hook: Processes.init(MyAlgo(), context)\nstep hook: Processes.step!(MyAlgo(), context)","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Internally the macro defines:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"struct MyAlgo <: ProcessAlgorithm end or Base.@kwdef struct MyAlgo ... end\na hidden implementation function containing the user body\npublic Processes.step!(algo::MyAlgo, ...) methods for direct calls\ngenerated Processes.init and Processes.step! methods that feed the implementation","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Type annotations and where clauses are preserved on the generated public call signatures and the hidden implementation function. The runtime context extraction methods currently bind simple locals before forwarding into that typed implementation.","category":"page"},{"location":"user/algorithms_states/#Analysis-Friendly-Forms","page":"Algorithms and States","title":"Analysis-Friendly Forms","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"If you want ContextAnalyser to discover dependencies more reliably:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"use @inputs((; ...)) to make init-time requirements explicit\nuse context.name or (; name) = context for required reads\nuse get(context, :name, default) for optional reads\nreturn plain NamedTuples from init and step!","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"See Init Analysis for the analyzer workflow and limitations.","category":"page"},{"location":"user/algorithms_states/#@ProcessState","page":"Algorithms and States","title":"@ProcessState","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessState creates a ProcessState and an init method.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"@ProcessState function SharedParams(dt)\n    return (; dt)\nend","category":"page"},{"location":"user/algorithms_states/#Composition","page":"Algorithms and States","title":"Composition","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Compose entities with loop algorithms:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"CompositeAlgorithm(...) for interleaved stepping with intervals.\nRoutine(...) for sequential blocks with repeats.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Both can include ProcessStates and user options such as Route and Share.","category":"page"},{"location":"user/algorithms_states/#Changing-a-Loop-Algorithm-Schedule","page":"Algorithms and States","title":"Changing a Loop Algorithm Schedule","text":"","category":"section"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"Process lifetime controls how long the outer process loop runs. Inside a loop algorithm, the per-child schedule is controlled by the loop algorithm itself:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"CompositeAlgorithm and ThreadedCompositeAlgorithm use intervals.\nRoutine uses repeats.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"For composite algorithms, use the edit helpers before resolving the algorithm:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"algo = CompositeAlgorithm(FastStep, SlowStep, (1, 10))\n\nalgo = changeinterval(algo, 2, 20)\ninterval(algo, 2) == Processes.Interval(20)\n\nalgo = changeintervals(algo, (1, 5))\nintervals(algo) == (Processes.Interval(1), Processes.Interval(5))","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"These helpers return a new loop algorithm with the updated schedule. They are intended for unresolved loop algorithms; if you already called resolve, edit the original algorithm and resolve it again.","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"When adding a child, pass the new child's schedule as the last argument:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"algo = addalgo(algo, :logger => Logger, 100)","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"For Routine, the constructor and addalgo schedule argument are repeat counts:","category":"page"},{"location":"user/algorithms_states/","page":"Algorithms and States","title":"Algorithms and States","text":"routine = Routine(Prepare, Train, (1, 50))\nroutine = addalgo(routine, :validate => Validate, 1)","category":"page"},{"location":"#Processes.jl","page":"Home","title":"Processes.jl","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Processes.jl helps you build Julia loops from small named pieces.","category":"page"},{"location":"","page":"Home","title":"Home","text":"An algorithm is a piece of loop code. It is a subtype of ProcessAlgorithm and usually defines Processes.step!.","category":"page"},{"location":"","page":"Home","title":"Home","text":"A state is a piece of setup data. It is a subtype of ProcessState and usually defines Processes.init.","category":"page"},{"location":"","page":"Home","title":"Home","text":"A process combines algorithms, states, inputs, and stop rules into a running loop. While it runs, values live in a context. Each algorithm or state gets its own named part of that context, called a subcontext.","category":"page"},{"location":"","page":"Home","title":"Home","text":"The package keeps context shapes stable after setup, so tight loops can stay fast while still letting you compose larger workflows.","category":"page"},{"location":"","page":"Home","title":"Home","text":"Start with the user documentation if you want to build processes with the package. The internals section is for understanding how registries, contexts, routing, and generated loops are implemented.","category":"page"},{"location":"","page":"Home","title":"Home","text":"If you are new to the package, read these first:","category":"page"},{"location":"","page":"Home","title":"Home","text":"Algorithms and States\nRunning, Wait, Fetch\nContexts and Indexing\nInit, Overrides, and Runtime Inputs\nRoutes and Shares\nComposite DSL","category":"page"},{"location":"#User-Documentation","page":"Home","title":"User Documentation","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Algorithms and States\nComposite DSL\nReferencing Algorithms\nContexts and Indexing\nInit Analysis\nRoutes and Shares\nInit, Overrides, and Runtime Inputs\nVars (Var Selectors)\nLifetime\nRunning, Wait, Fetch\nCopying Processes\nThreaded Process Managers\nValue Semantics and Unique","category":"page"},{"location":"#Internals","page":"Home","title":"Internals","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Registry Internals\nContext Internals\nRoutes and Shares Internals\nProcess Pipeline Internals","category":"page"},{"location":"user/lifetime/#lifetime_user","page":"Lifetime","title":"Lifetime","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"lifetime controls when a process loop stops.","category":"page"},{"location":"user/lifetime/#Most-Common-Usage","page":"Lifetime","title":"Most Common Usage","text":"","category":"section"},{"location":"user/lifetime/#Fixed-number-of-iterations","page":"Lifetime","title":"Fixed number of iterations","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p = Process(algo; repeats = 1_000)","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The repeats keyword is converted internally to Repeat(1000).","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"You can also pass the lifetime object explicitly:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p = Process(algo; lifetime = Repeat(1_000))","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"For Process, the lifetime keyword is reserved for Lifetime objects. Use repeats = ... for plain integer counts.","category":"page"},{"location":"user/lifetime/#Default-behavior","page":"Lifetime","title":"Default behavior","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"If you do not pass lifetime:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"most processes default to Indefinite()\nRoutine defaults to one pass (Repeat(1)) when lifetime = nothing","category":"page"},{"location":"user/lifetime/#Explicit-Lifetime-Types","page":"Lifetime","title":"Explicit Lifetime Types","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"These types are available in code:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Repeat(n)\nIndefinite()\nUntil(condition, selector)\nRepeatOrUntil(condition, n, selector)","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The exported AtLeast and AtLeastAtMost lifetime types are also available for less common \"minimum count plus condition\" rules.","category":"page"},{"location":"user/lifetime/#Changing-Lifetime","page":"Lifetime","title":"Changing Lifetime","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Set the process lifetime when constructing the process:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p = Process(algo; lifetime = Repeat(1_000))","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"For an existing process, build a fresh process from the same task description with a different lifetime:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"p2 = copyprocess(p; lifetime = Repeat(2_000))","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"This changes the outer process lifetime. It does not change how often child loop algorithms run inside a CompositeAlgorithm or Routine. Those schedules are loop-algorithm settings: use changeinterval, changeintervals, or the schedule argument to addalgo. See Algorithms and States.","category":"page"},{"location":"user/lifetime/#Until:-Stop-on-a-Condition","page":"Lifetime","title":"Until: Stop on a Condition","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Until checks a value from context each loop.   Here, condition(value) is a stop condition:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"true -> stop now\nfalse -> continue","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"A practical pattern is to use Var(...) as selector:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"counter = Counter()\n\np = Process(\n    counter;\n    lifetime = Until(\n        x -> x >= 100,\n        Var(counter, :count),\n    ),\n)","category":"page"},{"location":"user/lifetime/#RepeatOrUntil:-Max-Iterations-Or-Condition","page":"Lifetime","title":"RepeatOrUntil: Max Iterations Or Condition","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"RepeatOrUntil combines:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"a maximum number of iterations (n)\na stop condition like Until","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The loop stops at whichever happens first:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"repeat count reaches n, or\ncondition becomes true.","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Example:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"counter = Counter()\n\np = Process(\n    counter;\n    lifetime = RepeatOrUntil(\n        x -> x >= 100,   # stop condition\n        1_000,           # hard max iterations\n        Var(counter, :count),\n    ),\n)","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Important:","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"Use the same algorithm reference you used in Process(...) (same instance or same Unique variable).\nVar(:name) reads from globals (for example Var(:process)).\nThe safest current Until usage is a single selector value.","category":"page"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"For full Var details, see Vars (Var Selectors).","category":"page"},{"location":"user/lifetime/#Notes","page":"Lifetime","title":"Notes","text":"","category":"section"},{"location":"user/lifetime/","page":"Lifetime","title":"Lifetime","text":"The lifetime types are exported, so Repeat(10) and Processes.Repeat(10) both work after using Processes.\nManual stop and pause still work regardless of lifetime.","category":"page"},{"location":"user/routes_shares/#routes_shares_user","page":"Routes and Shares","title":"Routes and Shares","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route and Share make values from one algorithm or state visible to another.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Each algorithm or state owns a subcontext: its named part of the full process context. A route exposes selected names from one subcontext. A share exposes all names from one subcontext.","category":"page"},{"location":"user/routes_shares/#Referencing-Algorithms","page":"Routes and Shares","title":"Referencing Algorithms","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Recap:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Use the same reference style you used in composition (type, saved instance, or saved Unique variable).\nDo not target with a fresh object unless that exact object was inserted in the composition.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"For full examples, see Referencing Algorithms.","category":"page"},{"location":"user/routes_shares/#Route:-Specific-Variables","page":"Routes and Shares","title":"Route: Specific Variables","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route selected variables from source to target, optionally aliased:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"CompositeAlgorithm(\n    Source, Target,\n    (1, 1),\n    Route(Source => Target, :value => :input_value),\n)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Target sees context.input_value.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If no alias is given, the target sees the same name as the source.","category":"page"},{"location":"user/routes_shares/#Transform-Route-Values","page":"Routes and Shares","title":"Transform Route Values","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"You can provide transform = f (single mapping route) to expose transformed source values:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(Source => Target, :series => :latest, transform = x -> x[end])","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If the target may return the routed alias and you want that return written back through the transformed route, provide reverse_transform = g:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(\n    Source => Target,\n    :value => :input,\n    transform = x -> 2x,\n    reverse_transform = y -> y / 2,\n)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"In this example, Target reads context.input == 2 * Source.value. If Target returns (; input = new_input), Source.value is updated with new_input / 2.","category":"page"},{"location":"user/routes_shares/#Transform-From-Multiple-Source-Variables","page":"Routes and Shares","title":"Transform From Multiple Source Variables","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"A transform route can also read multiple source variables by using a tuple on the left-hand side:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Route(\n    Source => Target,\n    (:x, :y) => :norm_xy,\n    transform = (x, y) -> sqrt(x^2 + y^2),\n    reverse_transform = norm_xy -> (; x = norm_xy, y = 0.0),\n)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Important constraints from the current implementation:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If transform or reverse_transform is provided, the route must define exactly one mapping.\nMulti-source reverse transforms may return a tuple in source-variable order or a named tuple keyed by source variable name.\nReturning a transformed route alias without reverse_transform is an error, because the writeback would otherwise be ambiguous.","category":"page"},{"location":"user/routes_shares/#Share:-Whole-Subcontext","page":"Routes and Shares","title":"Share: Whole Subcontext","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Expose all source variables to target:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Share(Source, Target)","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Default is bidirectional (directional = false), so both sides can read the other side's values. Use directional = true for a one-way share from the first argument to the second.","category":"page"},{"location":"user/routes_shares/#Read-and-Write-Semantics","page":"Routes and Shares","title":"Read and Write Semantics","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Routed and shared names point back to stored values. If the target returns one of those names from step!, the source subcontext can be updated.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"This enables coupling patterns like:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"algorithm B reading and damping algorithm A's velocity, then returning updated velocity.","category":"page"},{"location":"user/routes_shares/#Plan-Local-Routes","page":"Routes and Shares","title":"Plan-Local Routes","text":"","category":"section"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Routes belong to the plan node where they are declared. In the DSL, a route statement inside a composite/routine is attached to that local child step, so the same algorithm type can be reused elsewhere with different local wiring.","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"Example:","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"@CompositeAlgorithm begin\n    c1 = @CompositeAlgorithm begin\n        inner = Source()\n    end\n    sink = Sink()\n    @route c1.inner.value => sink.value\nend","category":"page"},{"location":"user/routes_shares/","page":"Routes and Shares","title":"Routes and Shares","text":"If a local route and a broader route expose the same target alias, the local route takes precedence for that child step.","category":"page"}]
}
